{
  "name": "PEA Computer Asset Management",
  "description": "A modern web application for managing computer assets with real-time Google Sheets integration, per-column filtering, and inline editing features, designed with the PEA signature purple aesthetic."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ComputerAsset {
  id: string;
  Computername: string;
  User: string;
  Department: string;
  Model: string;
  SerialNo: string;
  Location: string;
  Status: string;
}

export type AssetFilter = {
  [K in keyof ComputerAsset]?: string;
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Monitor, 
  LayoutDashboard, 
  PlusCircle, 
  Settings, 
  Search, 
  LogOut, 
  Menu,
  X,
  Database,
  RefreshCw,
  Bell
} from 'lucide-react';
import AssetTable from './components/AssetTable';
import AddAssetModal from './components/AddAssetModal';
import { ComputerAsset } from './types';
import { fetchSheetData } from './services/sheetService';

const PEA_PURPLE = '#6C248C';

const App: React.FC = () => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [assets, setAssets] = useState<ComputerAsset[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);

  // Simulation of persistence since direct writing to public Sheets requires a backend/API
  const handleUpdateAsset = (id: string, newName: string) => {
    setAssets(prev => prev.map(asset => 
      asset.id === id ? { ...asset, Computername: newName } : asset
    ));
  };

  const handleAddAsset = (newAsset: Omit<ComputerAsset, 'id'>) => {
    const assetWithId = { ...newAsset, id: Math.random().toString(36).substr(2, 9) };
    setAssets(prev => [assetWithId, ...prev]);
    setShowAddModal(false);
  };

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const data = await fetchSheetData();
        setAssets(data);
      } catch (error) {
        console.error("Error fetching data:", error);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, [refreshKey]);

  return (
    <div className="flex h-screen overflow-hidden bg-gray-50">
      {/* Sidebar */}
      <aside 
        className={`${
          sidebarOpen ? 'w-72' : 'w-20'
        } transition-all duration-300 bg-[#6C248C] text-white flex flex-col shadow-xl z-20`}
      >
        <div className="p-6 flex items-center justify-between border-b border-purple-500/30">
          <div className={`flex items-center gap-3 overflow-hidden ${!sidebarOpen && 'hidden'}`}>
            <div className="bg-white p-1.5 rounded-lg">
              <Database className="text-[#6C248C] w-6 h-6" />
            </div>
            <span className="font-bold text-lg whitespace-nowrap">PEA Asset</span>
          </div>
          <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-1 hover:bg-purple-700 rounded-md">
            {sidebarOpen ? <X size={20} /> : <Menu size={24} className="mx-auto" />}
          </button>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          <SidebarItem 
            icon={<LayoutDashboard size={20} />} 
            label="Dashboard" 
            active={false} 
            collapsed={!sidebarOpen} 
          />
          <SidebarItem 
            icon={<Monitor size={20} />} 
            label="ข้อมูลทรัพย์สินคอมพิวเตอร์" 
            active={true} 
            collapsed={!sidebarOpen} 
          />
          <SidebarItem 
            icon={<Settings size={20} />} 
            label="Settings" 
            active={false} 
            collapsed={!sidebarOpen} 
          />
        </nav>

        <div className="p-4 border-t border-purple-500/30">
          <SidebarItem 
            icon={<LogOut size={20} />} 
            label="Logout" 
            active={false} 
            collapsed={!sidebarOpen} 
          />
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden">
        {/* Header */}
        <header className="h-16 bg-white border-b flex items-center justify-between px-8 shadow-sm">
          <h1 className="text-xl font-semibold text-gray-800">จัดการข้อมูลทรัพย์สินคอมพิวเตอร์</h1>
          <div className="flex items-center gap-4">
            <div className="relative">
              <Bell className="text-gray-500 cursor-pointer hover:text-purple-700" size={20} />
              <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] rounded-full w-4 h-4 flex items-center justify-center">3</span>
            </div>
            <div className="h-8 w-8 rounded-full bg-purple-100 border border-purple-200 flex items-center justify-center text-[#6C248C] font-bold text-sm cursor-pointer">
              AD
            </div>
          </div>
        </header>

        {/* Content Area */}
        <div className="flex-1 overflow-auto p-8">
          <div className="max-w-7xl mx-auto space-y-6">
            {/* Stats Summary */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <StatCard title="Total Assets" value={assets.length} color="bg-purple-600" />
              <StatCard title="Active Systems" value={assets.filter(a => a.Status === 'Active' || a.Status === 'ใช้งานปกติ').length} color="bg-green-500" />
              <StatCard title="Maintenance Needed" value={assets.filter(a => a.Status === 'Repair' || a.Status === 'ส่งซ่อม').length} color="bg-orange-500" />
            </div>

            {/* Actions Bar */}
            <div className="flex flex-col sm:flex-row justify-between items-center bg-white p-4 rounded-xl shadow-sm border gap-4">
              <div className="relative w-full sm:w-96">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
                <input 
                  type="text" 
                  placeholder="ค้นหาข้อมูลทรัพย์สิน..." 
                  className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all text-sm"
                />
              </div>
              <div className="flex items-center gap-3 w-full sm:w-auto">
                <button 
                  onClick={() => setRefreshKey(prev => prev + 1)}
                  className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg border transition-all"
                  title="Refresh Data"
                >
                  <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
                </button>
                <button 
                  onClick={() => setShowAddModal(true)}
                  className="flex items-center justify-center gap-2 bg-[#6C248C] hover:bg-[#5a1e75] text-white px-6 py-2 rounded-lg font-medium shadow-md shadow-purple-200 transition-all w-full sm:w-auto"
                >
                  <PlusCircle size={18} />
                  <span>เพิ่มข้อมูลใหม่</span>
                </button>
              </div>
            </div>

            {/* Asset Table Container */}
            <div className="bg-white rounded-xl shadow-md border overflow-hidden">
              <AssetTable 
                assets={assets} 
                onUpdateAsset={handleUpdateAsset} 
                loading={loading}
              />
            </div>
          </div>
        </div>
      </main>

      {/* Add Modal */}
      {showAddModal && (
        <AddAssetModal 
          onClose={() => setShowAddModal(false)} 
          onSubmit={handleAddAsset} 
        />
      )}
    </div>
  );
};

// Helper Components
const SidebarItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, collapsed: boolean }> = ({ icon, label, active, collapsed }) => (
  <div className={`flex items-center gap-4 px-4 py-3 rounded-lg cursor-pointer transition-all ${
    active ? 'bg-white/20 text-white font-semibold' : 'text-purple-100 hover:bg-white/10 hover:text-white'
  }`}>
    <div className="min-w-[20px]">{icon}</div>
    {!collapsed && <span className="whitespace-nowrap truncate">{label}</span>}
  </div>
);

const StatCard: React.FC<{ title: string, value: number, color: string }> = ({ title, value, color }) => (
  <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex items-center justify-between">
    <div>
      <p className="text-gray-500 text-sm font-medium">{title}</p>
      <p className="text-3xl font-bold text-gray-800 mt-1">{value}</p>
    </div>
    <div className={`w-12 h-12 rounded-full ${color} flex items-center justify-center text-white shadow-lg opacity-80`}>
      <Monitor size={24} />
    </div>
  </div>
);

export default App;

import React, { useState } from 'react';
import { Edit2, Check, X, Filter, Monitor } from 'lucide-react';
import { ComputerAsset, AssetFilter } from '../types';

interface AssetTableProps {
  assets: ComputerAsset[];
  onUpdateAsset: (id: string, newName: string) => void;
  loading: boolean;
}

const AssetTable: React.FC<AssetTableProps> = ({ assets, onUpdateAsset, loading }) => {
  const [filters, setFilters] = useState<AssetFilter>({});
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  const handleFilterChange = (key: keyof ComputerAsset, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const filteredAssets = assets.filter(asset => {
    return Object.entries(filters).every(([key, value]) => {
      if (!value) return true;
      const assetValue = asset[key as keyof ComputerAsset]?.toString().toLowerCase() || '';
      return assetValue.includes(value.toLowerCase());
    });
  });

  const startEdit = (asset: ComputerAsset) => {
    setEditingId(asset.id);
    setEditValue(asset.Computername);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditValue('');
  };

  const saveEdit = (id: string) => {
    onUpdateAsset(id, editValue);
    setEditingId(null);
    setEditValue('');
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 space-y-4">
        <div className="w-12 h-12 border-4 border-[#6C248C] border-t-transparent rounded-full animate-spin"></div>
        <p className="text-gray-500 font-medium">กำลังโหลดข้อมูลจาก Google Sheet...</p>
      </div>
    );
  }

  return (
    <div className="overflow-x-auto relative">
      <table className="w-full text-left border-collapse">
        <thead>
          <tr className="bg-gray-50 border-b border-gray-200">
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Computer Name
              <FilterInput column="Computername" value={filters.Computername || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              User
              <FilterInput column="User" value={filters.User || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Department
              <FilterInput column="Department" value={filters.Department || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Model
              <FilterInput column="Model" value={filters.Model || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Serial No.
              <FilterInput column="SerialNo" value={filters.SerialNo || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Status
              <FilterInput column="Status" value={filters.Status || ''} onChange={handleFilterChange} />
            </th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {filteredAssets.length > 0 ? (
            filteredAssets.map((asset) => (
              <tr key={asset.id} className="hover:bg-purple-50/30 transition-colors">
                <td className="px-6 py-4">
                  {editingId === asset.id ? (
                    <div className="flex items-center gap-2">
                      <input 
                        type="text" 
                        value={editValue} 
                        onChange={(e) => setEditValue(e.target.value)}
                        className="border border-purple-400 rounded px-2 py-1 text-sm focus:outline-none focus:ring-2 focus:ring-purple-200 w-full"
                        autoFocus
                      />
                      <button onClick={() => saveEdit(asset.id)} className="text-green-600 hover:bg-green-100 p-1 rounded">
                        <Check size={16} />
                      </button>
                      <button onClick={cancelEdit} className="text-red-500 hover:bg-red-100 p-1 rounded">
                        <X size={16} />
                      </button>
                    </div>
                  ) : (
                    <div className="flex items-center justify-between group">
                      <span className="font-medium text-gray-800">{asset.Computername}</span>
                      <button 
                        onClick={() => startEdit(asset)} 
                        className="opacity-0 group-hover:opacity-100 transition-opacity text-[#6C248C] p-1.5 hover:bg-purple-100 rounded-lg"
                      >
                        <Edit2 size={14} />
                      </button>
                    </div>
                  )}
                </td>
                <td className="px-6 py-4 text-sm text-gray-600">{asset.User}</td>
                <td className="px-6 py-4 text-sm text-gray-600">{asset.Department}</td>
                <td className="px-6 py-4 text-sm text-gray-600">{asset.Model}</td>
                <td className="px-6 py-4 text-sm text-gray-600">{asset.SerialNo}</td>
                <td className="px-6 py-4 text-sm">
                  <StatusBadge status={asset.Status} />
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan={6} className="px-6 py-12 text-center text-gray-400">
                ไม่พบข้อมูลที่ตรงกับเงื่อนไขการค้นหา
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

// Filter Input Helper Component
const FilterInput: React.FC<{ column: keyof ComputerAsset, value: string, onChange: (key: keyof ComputerAsset, val: string) => void }> = ({ column, value, onChange }) => (
  <div className="mt-2 relative">
    <input 
      type="text" 
      placeholder={`Filter ${column}...`}
      value={value}
      onChange={(e) => onChange(column, e.target.value)}
      className="w-full px-2 py-1 text-[10px] font-normal border border-gray-200 rounded focus:border-purple-400 focus:outline-none bg-white normal-case"
    />
  </div>
);

const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
  const isGood = status?.toLowerCase().includes('active') || status?.toLowerCase().includes('ปกติ') || status?.toLowerCase().includes('ใช้งาน');
  return (
    <span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide ${
      isGood ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
    }`}>
      {status || 'Unknown'}
    </span>
  );
}

export default AssetTable;

import React, { useState } from 'react';
import { X, Save, AlertCircle } from 'lucide-react';
import { ComputerAsset } from '../types';

interface AddAssetModalProps {
  onClose: () => void;
  onSubmit: (asset: Omit<ComputerAsset, 'id'>) => void;
}

const AddAssetModal: React.FC<AddAssetModalProps> = ({ onClose, onSubmit }) => {
  const [formData, setFormData] = useState<Omit<ComputerAsset, 'id'>>({
    Computername: '',
    User: '',
    Department: '',
    Model: '',
    SerialNo: '',
    Location: '',
    Status: 'Active'
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.Computername || !formData.User) {
      alert("กรุณากรอกข้อมูลที่จำเป็น (Computer Name และ User)");
      return;
    }
    onSubmit(formData);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
        {/* Header */}
        <div className="bg-[#6C248C] px-6 py-4 flex items-center justify-between text-white">
          <div className="flex items-center gap-2">
            <div className="bg-white/20 p-1.5 rounded-lg">
              <Save size={20} />
            </div>
            <h3 className="text-xl font-bold">เพิ่มข้อมูลทรัพย์สินใหม่</h3>
          </div>
          <button onClick={onClose} className="p-1.5 hover:bg-white/10 rounded-full transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Form Body */}
        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-1.5">
              <label className="text-sm font-semibold text-gray-700 flex items-center gap-1">
                Computer Name <span className="text-red-500">*</span>
              </label>
              <input 
                name="Computername"
                required
                value={formData.Computername}
                onChange={handleChange}
                placeholder="เช่น PEA-WK-001"
                className="w-full border border-gray-300 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-purple-200 focus:border-[#6C248C] transition-all outline-none"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-sm font-semibold text-gray-700 flex items-center gap-1">
                User <span className="text-red-500">*</span>
              </label>
              <input 
                name="User"
                required
                value={formData.User}
                onChange={handleChange}
                placeholder="ชื่อ-นามสกุล พนักงาน"
                className="w-full border border-gray-300 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-purple-200 focus:border-[#6C248C] transition-all outline-none"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-sm font-semibold text-gray-700">Department</label>
              <input 
                name="Department"
                value={formData.Department}
                onChange={handleChange}
                placeholder="เช่น กบอ. (ธ.)"
                className="w-full border border-gray-300 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-purple-200 focus:border-[#6C248C] transition-all outline-none"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-sm font-semibold text-gray-700">Model</label>
              <input 
                name="Model"
                value={formData.Model}
                onChange={handleChange}
                placeholder="เช่น HP ProDesk 600 G6"
                className="w-full border border-gray-300 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-purple-200 focus:border-[#6C248C] transition-all outline-none"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-sm font-semibold text-gray-700">Serial No.</label>
              <input 
                name="SerialNo"
                value={formData.SerialNo}
                onChange={handleChange}
                placeholder="หมายเลขซีเรียล"
                className="w-full border border-gray-300 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-purple-200 focus:border-[#6C248C] transition-all outline-none"
              />
            </div>

            <div className="space-y-1.5">
              <label className="text-sm font-semibold text-gray-700">Status</label>
              <select 
                name="Status"
                value={formData.Status}
                onChange={handleChange}
                className="w-full border border-gray-300 rounded-lg px-4 py-2.5 focus:ring-2 focus:ring-purple-200 focus:border-[#6C248C] transition-all outline-none bg-white"
              >
                <option value="Active">Active (ใช้งานปกติ)</option>
                <option value="Repair">Repair (ส่งซ่อม)</option>
                <option value="Storage">Storage (เก็บเข้าคลัง)</option>
                <option value="Retired">Retired (จำหน่ายออก)</option>
              </select>
            </div>
          </div>

          <div className="flex items-center gap-2 p-3 bg-blue-50 text-blue-700 rounded-lg text-xs">
            <AlertCircle size={16} />
            <span>ข้อมูลนี้จะถูกจัดเก็บเข้าสู่ระบบคลาวด์ของฝ่ายไอทีโดยอัตโนมัติ</span>
          </div>

          {/* Footer Actions */}
          <div className="flex items-center justify-end gap-3 pt-4 border-t">
            <button 
              type="button"
              onClick={onClose}
              className="px-6 py-2.5 rounded-lg border border-gray-300 text-gray-600 hover:bg-gray-50 font-medium transition-all"
            >
              ยกเลิก
            </button>
            <button 
              type="submit"
              className="px-8 py-2.5 rounded-lg bg-[#6C248C] text-white hover:bg-[#5a1e75] font-bold shadow-lg shadow-purple-100 transition-all"
            >
              บันทึกข้อมูล
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddAssetModal;

import { ComputerAsset } from '../types';

const SHEET_ID = '1hoKlhjJ4mK61mwtkZx0EocFg-vqvXVmF0f8A-D27y5U';
// We use the visualization API query to get CSV data from a public sheet
const CSV_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:csv`;

export const fetchSheetData = async (): Promise<ComputerAsset[]> => {
  try {
    const response = await fetch(CSV_URL);
    const text = await response.text();

    // Simple CSV parser
    const rows = text.split('\n').map(row => {
      // Handle quoted values containing commas
      const matches = row.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g);
      return (matches || []).map(val => val.replace(/^"|"$/g, ''));
    });

    if (rows.length <= 1) return [];

    const headers = rows[0];

    // Mapping spreadsheet columns to our object keys
    // This assumes the sheet has headers like Computername, User, etc.
    // If headers differ, we map by index as a fallback
    return rows.slice(1).map((row, idx) => ({
      id: `row-${idx}`,
      Computername: row[0] || '',
      User: row[1] || '',
      Department: row[2] || '',
      Model: row[3] || '',
      SerialNo: row[4] || '',
      Location: row[5] || '',
      Status: row[6] || 'Active'
    }));
  } catch (error) {
    console.error("Fetch Error:", error);
    // Return dummy data if fetch fails for demo purposes
    return [
      { id: '1', Computername: 'PEA-D-01', User: 'นายสมชาย ใจดี', Department: 'กบอ.', Model: 'HP ProBook', SerialNo: 'SN001', Location: 'ชั้น 2', Status: 'Active' },
      { id: '2', Computername: 'PEA-D-02', User: 'นางสาวนรีวรรณ สวยงาม', Department: 'กพส.', Model: 'Dell Latitude', SerialNo: 'SN002', Location: 'ชั้น 3', Status: 'Repair' },
      { id: '3', Computername: 'PEA-D-03', User: 'นายวิเชียร ทองใบ', Department: 'กงบ.', Model: 'Lenovo ThinkPad', SerialNo: 'SN003', Location: 'ชั้น 1', Status: 'Active' },
    ];
  }
};

