import React, { useState } from 'react';
import { Edit2, Check, X, Filter, Monitor } from 'lucide-react';
import { ComputerAsset, AssetFilter } from '../types';

interface AssetTableProps {
  assets: ComputerAsset[];
  onUpdateAsset: (id: string, newName: string) => void;
  loading: boolean;
}

const AssetTable: React.FC<AssetTableProps> = ({ assets, onUpdateAsset, loading }) => {
  const [filters, setFilters] = useState<AssetFilter>({});
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  const handleFilterChange = (key: keyof ComputerAsset, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  const filteredAssets = assets.filter(asset => {
    return Object.entries(filters).every(([key, value]) => {
      if (!value) return true;
      const assetValue = asset[key as keyof ComputerAsset]?.toString().toLowerCase() || '';
      // Fix: cast 'value' as string to ensure 'toLowerCase' is accessible on the filter value
      return assetValue.includes((value as string).toLowerCase());
    });
  });

  const startEdit = (asset: ComputerAsset) => {
    setEditingId(asset.id);
    setEditValue(asset.Computername);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditValue('');
  };

  const saveEdit = (id: string) => {
    onUpdateAsset(id, editValue);
    setEditingId(null);
    setEditValue('');
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 space-y-4">
        <div className="w-12 h-12 border-4 border-[#6C248C] border-t-transparent rounded-full animate-spin"></div>
        <p className="text-gray-500 font-medium">กำลังโหลดข้อมูลจาก Google Sheet...</p>
      </div>
    );
  }

  return (
    <div className="overflow-x-auto relative">
      <table className="w-full text-left border-collapse">
        <thead>
          <tr className="bg-gray-50 border-b border-gray-200">
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Computer Name
              <FilterInput column="Computername" value={filters.Computername || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              User
              <FilterInput column="User" value={filters.User || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Department
              <FilterInput column="Department" value={filters.Department || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Model
              <FilterInput column="Model" value={filters.Model || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Serial No.
              <FilterInput column="SerialNo" value={filters.SerialNo || ''} onChange={handleFilterChange} />
            </th>
            <th className="px-6 py-4 text-xs font-semibold text-gray-600 uppercase tracking-wider">
              Status
              <FilterInput column="Status" value={filters.Status || ''} onChange={handleFilterChange} />
            </th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100">
          {filteredAssets.length > 0 ? (
            filteredAssets.map((asset) => (
              <tr key={asset.id} className="hover:bg-purple-50/30 transition-colors">
                <td className="px-6 py-4">
                  {editingId === asset.id ? (
                    <div className="flex items-center gap-2">
                      <input 
                        type="text" 
                        value={editValue} 
                        onChange={(e) => setEditValue(e.target.value)}
                        className="border border-purple-400 rounded px-2 py-1 text-sm focus:outline-none focus:ring-2 focus:ring-purple-200 w-full"
                        autoFocus
                      />
                      <button onClick={() => saveEdit(asset.id)} className="text-green-600 hover:bg-green-100 p-1 rounded">
                        <Check size={16} />
                      </button>
                      <button onClick={cancelEdit} className="text-red-500 hover:bg-red-100 p-1 rounded">
                        <X size={16} />
                      </button>
                    </div>
                  ) : (
                    <div className="flex items-center justify-between group">
                      <span className="font-medium text-gray-800">{asset.Computername}</span>
                      <button 
                        onClick={() => startEdit(asset)} 
                        className="opacity-0 group-hover:opacity-100 transition-opacity text-[#6C248C] p-1.5 hover:bg-purple-100 rounded-lg"
                      >
                        <Edit2 size={14} />
                      </button>
                    </div>
                  )}
                </td>
                <td className="px-6 py-4 text-sm text-gray-600">{asset.User}</td>
                <td className="px-6 py-4 text-sm text-gray-600">{asset.Department}</td>
                <td className="px-6 py-4 text-sm text-gray-600">{asset.Model}</td>
                <td className="px-6 py-4 text-sm text-gray-600">{asset.SerialNo}</td>
                <td className="px-6 py-4 text-sm">
                  <StatusBadge status={asset.Status} />
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan={6} className="px-6 py-12 text-center text-gray-400">
                ไม่พบข้อมูลที่ตรงกับเงื่อนไขการค้นหา
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

// Filter Input Helper Component
const FilterInput: React.FC<{ column: keyof ComputerAsset, value: string, onChange: (key: keyof ComputerAsset, val: string) => void }> = ({ column, value, onChange }) => (
  <div className="mt-2 relative">
    <input 
      type="text" 
      placeholder={`Filter ${column}...`}
      value={value}
      onChange={(e) => onChange(column, e.target.value)}
      className="w-full px-2 py-1 text-[10px] font-normal border border-gray-200 rounded focus:border-purple-400 focus:outline-none bg-white normal-case"
    />
  </div>
);

const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
  const isGood = status?.toLowerCase().includes('active') || status?.toLowerCase().includes('ปกติ') || status?.toLowerCase().includes('ใช้งาน');
  return (
    <span className={`px-2 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide ${
      isGood ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
    }`}>
      {status || 'Unknown'}
    </span>
  );
}

export default AssetTable;

import React, { useState, useMemo, useEffect } from 'react';
import { Edit2, Check, X, Filter, ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from 'lucide-react';
import { ComputerAsset, AssetFilter } from '../types';

interface AssetTableProps {
  assets: ComputerAsset[];
  onUpdateAsset: (id: string, newName: string) => void;
  loading: boolean;
}

const ITEMS_PER_PAGE = 50;

const AssetTable: React.FC<AssetTableProps> = ({ assets, onUpdateAsset, loading }) => {
  const [filters, setFilters] = useState<AssetFilter>({});
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [currentPage, setCurrentPage] = useState(1);

  // Reset to page 1 when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [filters]);

  const handleFilterChange = (key: keyof ComputerAsset, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  // Efficiently filter the assets
  const filteredAssets = useMemo(() => {
    return assets.filter(asset => {
      return Object.entries(filters).every(([key, value]) => {
        if (!value) return true;
        const assetValue = asset[key as keyof ComputerAsset]?.toString().toLowerCase() || '';
        return assetValue.includes((value as string).toLowerCase());
      });
    });
  }, [assets, filters]);

  // Calculate pagination
  const totalItems = filteredAssets.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const paginatedAssets = useMemo(() => {
    return filteredAssets.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredAssets, startIndex]);

  const startEdit = (asset: ComputerAsset) => {
    setEditingId(asset.id);
    setEditValue(asset.Computername);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditValue('');
  };

  const saveEdit = (id: string) => {
    onUpdateAsset(id, editValue);
    setEditingId(null);
    setEditValue('');
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 space-y-4">
        <div className="w-12 h-12 border-4 border-[#6C248C] border-t-transparent rounded-full animate-spin"></div>
        <p className="text-gray-500 font-medium">กำลังโหลดข้อมูลจำนวนมาก กรุณารอสักครู่...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full">
      <div className="overflow-x-auto relative flex-1">
        <table className="w-full text-left border-collapse min-w-[1000px]">
          <thead>
            <tr className="bg-gray-50 border-b border-gray-200">
              <th className="px-6 py-4 text-xs font-bold text-gray-600 uppercase tracking-wider sticky top-0 bg-gray-50 z-10">
                Computer Name
                <FilterInput column="Computername" value={filters.Computername || ''} onChange={handleFilterChange} />
              </th>
              <th className="px-6 py-4 text-xs font-bold text-gray-600 uppercase tracking-wider sticky top-0 bg-gray-50 z-10">
                User
                <FilterInput column="User" value={filters.User || ''} onChange={handleFilterChange} />
              </th>
              <th className="px-6 py-4 text-xs font-bold text-gray-600 uppercase tracking-wider sticky top-0 bg-gray-50 z-10">
                Department
                <FilterInput column="Department" value={filters.Department || ''} onChange={handleFilterChange} />
              </th>
              <th className="px-6 py-4 text-xs font-bold text-gray-600 uppercase tracking-wider sticky top-0 bg-gray-50 z-10">
                Model
                <FilterInput column="Model" value={filters.Model || ''} onChange={handleFilterChange} />
              </th>
              <th className="px-6 py-4 text-xs font-bold text-gray-600 uppercase tracking-wider sticky top-0 bg-gray-50 z-10">
                Serial No.
                <FilterInput column="SerialNo" value={filters.SerialNo || ''} onChange={handleFilterChange} />
              </th>
              <th className="px-6 py-4 text-xs font-bold text-gray-600 uppercase tracking-wider sticky top-0 bg-gray-50 z-10">
                Status
                <FilterInput column="Status" value={filters.Status || ''} onChange={handleFilterChange} />
              </th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {paginatedAssets.length > 0 ? (
              paginatedAssets.map((asset) => (
                <tr key={asset.id} className="hover:bg-purple-50/30 transition-colors">
                  <td className="px-6 py-3">
                    {editingId === asset.id ? (
                      <div className="flex items-center gap-2">
                        <input 
                          type="text" 
                          value={editValue} 
                          onChange={(e) => setEditValue(e.target.value)}
                          className="border border-purple-400 rounded px-2 py-1 text-sm focus:outline-none focus:ring-2 focus:ring-purple-200 w-full"
                          autoFocus
                        />
                        <button onClick={() => saveEdit(asset.id)} className="text-green-600 hover:bg-green-100 p-1 rounded transition-colors">
                          <Check size={16} />
                        </button>
                        <button onClick={cancelEdit} className="text-red-500 hover:bg-red-100 p-1 rounded transition-colors">
                          <X size={16} />
                        </button>
                      </div>
                    ) : (
                      <div className="flex items-center justify-between group">
                        <span className="font-medium text-gray-800">{asset.Computername}</span>
                        <button 
                          onClick={() => startEdit(asset)} 
                          className="opacity-0 group-hover:opacity-100 transition-opacity text-[#6C248C] p-1.5 hover:bg-purple-100 rounded-lg"
                          title="แก้ไข Computer Name"
                        >
                          <Edit2 size={14} />
                        </button>
                      </div>
                    )}
                  </td>
                  <td className="px-6 py-3 text-sm text-gray-600">{asset.User}</td>
                  <td className="px-6 py-3 text-sm text-gray-600">{asset.Department}</td>
                  <td className="px-6 py-3 text-sm text-gray-600">{asset.Model}</td>
                  <td className="px-6 py-3 text-sm text-gray-600">{asset.SerialNo}</td>
                  <td className="px-6 py-3 text-sm">
                    <StatusBadge status={asset.Status} />
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={6} className="px-6 py-12 text-center text-gray-400">
                  ไม่พบข้อมูลที่ตรงกับเงื่อนไขการค้นหา
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination Controls */}
      <div className="bg-gray-50 border-t border-gray-200 px-6 py-4 flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="text-sm text-gray-600">
          แสดง <span className="font-semibold text-gray-900">{totalItems > 0 ? startIndex + 1 : 0}</span> ถึง <span className="font-semibold text-gray-900">{Math.min(startIndex + ITEMS_PER_PAGE, totalItems)}</span> จากทั้งหมด <span className="font-semibold text-gray-900">{totalItems.toLocaleString()}</span> รายการ
        </div>

        <div className="flex items-center gap-2">
          <PaginationButton 
            onClick={() => setCurrentPage(1)} 
            disabled={currentPage === 1}
            icon={<ChevronsLeft size={18} />}
          />
          <PaginationButton 
            onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} 
            disabled={currentPage === 1}
            icon={<ChevronLeft size={18} />}
          />

          <div className="flex items-center gap-1 px-2">
            <span className="text-sm font-medium text-gray-700">หน้า</span>
            <input 
              type="number" 
              min={1} 
              max={totalPages}
              value={currentPage}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                if (!isNaN(val) && val >= 1 && val <= totalPages) setCurrentPage(val);
              }}
              className="w-12 text-center border border-gray-300 rounded-md py-1 text-sm focus:ring-1 focus:ring-purple-500 focus:outline-none"
            />
            <span className="text-sm font-medium text-gray-700">จาก {totalPages}</span>
          </div>

          <PaginationButton 
            onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} 
            disabled={currentPage === totalPages || totalPages === 0}
            icon={<ChevronRight size={18} />}
          />
          <PaginationButton 
            onClick={() => setCurrentPage(totalPages)} 
            disabled={currentPage === totalPages || totalPages === 0}
            icon={<ChevronsRight size={18} />}
          />
        </div>
      </div>
    </div>
  );
};

// Helper Components
const FilterInput: React.FC<{ column: keyof ComputerAsset, value: string, onChange: (key: keyof ComputerAsset, val: string) => void }> = ({ column, value, onChange }) => (
  <div className="mt-2 relative">
    <input 
      type="text" 
      placeholder={`กรอง ${column}...`}
      value={value}
      onChange={(e) => onChange(column, e.target.value)}
      className="w-full px-2 py-1.5 text-[11px] font-normal border border-gray-300 rounded focus:border-purple-500 focus:ring-1 focus:ring-purple-200 focus:outline-none bg-white normal-case transition-all shadow-sm"
    />
  </div>
);

const PaginationButton: React.FC<{ onClick: () => void, disabled: boolean, icon: React.ReactNode }> = ({ onClick, disabled, icon }) => (
  <button 
    onClick={onClick}
    disabled={disabled}
    className={`p-2 rounded-lg border transition-all ${
      disabled 
      ? 'text-gray-300 bg-gray-50 border-gray-200 cursor-not-allowed' 
      : 'text-gray-600 bg-white border-gray-300 hover:bg-purple-50 hover:border-purple-300 hover:text-[#6C248C]'
    }`}
  >
    {icon}
  </button>
);

const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
  const isGood = status?.toLowerCase().includes('active') || status?.toLowerCase().includes('ปกติ') || status?.toLowerCase().includes('ใช้งาน');
  return (
    <span className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider shadow-sm ${
      isGood ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-red-100 text-red-700 border border-red-200'
    }`}>
      {status || 'Unknown'}
    </span>
  );
}

export default AssetTable;

