const SHEET_ID = '1hoKlhjJ4mK61mwtkZx0EocFg-vqvXVmF0f8A-D27y5U';
// We use the visualization API query to get CSV data from a public sheet
const CSV_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:csv`;

export const fetchSheetData = async (): Promise<ComputerAsset[]> => {
  try {
    const response = await fetch(CSV_URL);
    if (!response.ok) throw new Error('Network response was not ok');

    const text = await response.text();

    // Improved CSV parser for large datasets
    // This handles quoted commas more reliably and faster
    const rows: string[][] = [];
    const lines = text.split(/\r?\n/);

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i].trim();
      if (!line) continue;

      const parts = [];
      let currentPart = '';
      let inQuotes = false;

      for (let j = 0; j < line.length; j++) {
        const char = line[j];
        if (char === '"') {
          inQuotes = !inQuotes;
        } else if (char === ',' && !inQuotes) {
          parts.push(currentPart.trim());
          currentPart = '';
        } else {
          currentPart += char;
        }
      }
      parts.push(currentPart.trim());
      rows.push(parts);
    }

    if (rows.length <= 1) return [];

    // Mapping rows to ComputerAsset objects
    // We skip the first row (headers)
    return rows.slice(1).map((row, idx) => ({
      id: `row-${idx}`,
      Computername: row[0] || '',
      User: row[1] || '',
      Department: row[2] || '',
      Model: row[3] || '',
      SerialNo: row[4] || '',
      Location: row[5] || '',
      Status: row[6] || 'Active'
    }));
  } catch (error) {
    console.error("Fetch Error:", error);
    // Return empty array or local storage backup if fetch fails
    return [];
  }
};

import { ComputerAsset } from '../types';

const SHEET_ID = '1hoKlhjJ4mK61mwtkZx0EocFg-vqvXVmF0f8A-D27y5U';
const CSV_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:csv`;

export const fetchSheetData = async (): Promise<{data: any[], headers: string[]}> => {
  try {
    const response = await fetch(CSV_URL);
    if (!response.ok) throw new Error('Network response was not ok');

    const text = await response.text();
    const rows: string[][] = [];
    const lines = text.split(/\r?\n/);

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i].trim();
      if (!line) continue;

      const parts = [];
      let currentPart = '';
      let inQuotes = false;

      for (let j = 0; j < line.length; j++) {
        const char = line[j];
        if (char === '"') {
          inQuotes = !inQuotes;
        } else if (char === ',' && !inQuotes) {
          parts.push(currentPart.trim());
          currentPart = '';
        } else {
          currentPart += char;
        }
      }
      parts.push(currentPart.trim());
      rows.push(parts);
    }

    if (rows.length <= 1) return { data: [], headers: [] };

    const rawHeaders = rows[0];
    const data = rows.slice(1).map((row, idx) => {
      const obj: any = { id: `row-${idx}` };
      rawHeaders.forEach((header, colIdx) => {
        obj[header] = row[colIdx] || '';
      });
      return obj;
    });

    return { data, headers: rawHeaders };
  } catch (error) {
    console.error("Fetch Error:", error);
    return { data: [], headers: [] };
  }
};

