import React, { useState, useMemo, useEffect } from 'react';
import { Edit2, Check, X, Filter, ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from 'lucide-react';

interface AssetTableProps {
  assets: any[];
  headers: string[];
  onUpdateAsset: (id: string, newName: string) => void;
  loading: boolean;
}

const ITEMS_PER_PAGE = 50;

const AssetTable: React.FC<AssetTableProps> = ({ assets, headers, onUpdateAsset, loading }) => {
  const [filters, setFilters] = useState<Record<string, string>>({});
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [currentPage, setCurrentPage] = useState(1);

  useEffect(() => {
    setCurrentPage(1);
  }, [filters]);

  const handleFilterChange = (header: string, value: string) => {
    setFilters(prev => ({ ...prev, [header]: value }));
  };

  const filteredAssets = useMemo(() => {
    return assets.filter(asset => {
      return Object.entries(filters).every(([key, value]) => {
        if (!value) return true;
        const assetValue = asset[key]?.toString().toLowerCase() || '';
        return assetValue.includes(value.toLowerCase());
      });
    });
  }, [assets, filters]);

  const totalItems = filteredAssets.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;

  const paginatedAssets = useMemo(() => {
    return filteredAssets.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredAssets, startIndex]);

  const startEdit = (asset: any) => {
    setEditingId(asset.id);
    // Find the Computername key (case-insensitive)
    const key = headers.find(h => h.toLowerCase().includes('computername')) || headers[0];
    setEditValue(asset[key]);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditValue('');
  };

  const saveEdit = (id: string) => {
    onUpdateAsset(id, editValue);
    setEditingId(null);
    setEditValue('');
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-20 space-y-4 flex-1">
        <div className="w-12 h-12 border-4 border-[#6C248C] border-t-transparent rounded-full animate-spin"></div>
        <p className="text-gray-500 font-medium">กำลังโหลดและจัดรูปแบบข้อมูล {assets.length > 0 ? assets.length : '12,000+'} รายการ...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="overflow-auto relative flex-1">
        <table className="w-full text-left border-collapse min-w-max">
          <thead>
            <tr className="bg-gray-50 border-b border-gray-200 sticky top-0 z-10 shadow-sm">
              {headers.map((header) => (
                <th key={header} className="px-6 py-4 text-[11px] font-bold text-gray-600 uppercase tracking-wider bg-gray-50">
                  <div className="flex flex-col gap-2">
                    <span>{header}</span>
                    <input 
                      type="text" 
                      placeholder={`กรอง ${header}...`}
                      value={filters[header] || ''}
                      onChange={(e) => handleFilterChange(header, e.target.value)}
                      className="w-full px-2 py-1.5 text-[10px] font-normal border border-gray-200 rounded focus:border-purple-500 focus:ring-1 focus:ring-purple-200 focus:outline-none bg-white normal-case shadow-sm"
                    />
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {paginatedAssets.length > 0 ? (
              paginatedAssets.map((asset) => (
                <tr key={asset.id} className="hover:bg-purple-50/40 transition-colors">
                  {headers.map((header) => {
                    const isComputerName = header.toLowerCase().includes('computername');
                    return (
                      <td key={`${asset.id}-${header}`} className="px-6 py-3 text-sm text-gray-700 whitespace-nowrap">
                        {isComputerName && editingId === asset.id ? (
                          <div className="flex items-center gap-2 min-w-[200px]">
                            <input 
                              type="text" 
                              value={editValue} 
                              onChange={(e) => setEditValue(e.target.value)}
                              className="border border-purple-400 rounded px-2 py-1 text-sm focus:outline-none w-full shadow-inner"
                              autoFocus
                            />
                            <button onClick={() => saveEdit(asset.id)} className="text-green-600 hover:bg-green-100 p-1 rounded">
                              <Check size={16} />
                            </button>
                            <button onClick={cancelEdit} className="text-red-500 hover:bg-red-100 p-1 rounded">
                              <X size={16} />
                            </button>
                          </div>
                        ) : (
                          <div className="flex items-center justify-between group gap-4">
                            <span className={isComputerName ? 'font-semibold text-[#6C248C]' : ''}>
                              {asset[header]}
                            </span>
                            {isComputerName && (
                              <button 
                                onClick={() => startEdit(asset)} 
                                className="opacity-0 group-hover:opacity-100 transition-opacity text-gray-400 hover:text-[#6C248C] p-1 rounded-md"
                              >
                                <Edit2 size={13} />
                              </button>
                            )}
                          </div>
                        )}
                      </td>
                    );
                  })}
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={headers.length} className="px-6 py-12 text-center text-gray-400">
                  ไม่พบข้อมูลที่ตรงกับเงื่อนไขการกรอง
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="bg-white border-t border-gray-200 px-6 py-3 flex flex-col sm:flex-row items-center justify-between gap-4 z-20">
        <div className="text-sm text-gray-500">
          แสดง <span className="font-semibold text-gray-900">{totalItems > 0 ? startIndex + 1 : 0}</span>-
          <span className="font-semibold text-gray-900">{Math.min(startIndex + ITEMS_PER_PAGE, totalItems)}</span> จาก 
          <span className="font-semibold text-gray-900 ml-1">{totalItems.toLocaleString()}</span> รายการ
        </div>

        <div className="flex items-center gap-1.5">
          <PaginationButton onClick={() => setCurrentPage(1)} disabled={currentPage === 1} icon={<ChevronsLeft size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} icon={<ChevronLeft size={16} />} />

          <div className="mx-2 flex items-center gap-2">
            <span className="text-xs text-gray-500">หน้า</span>
            <input 
              type="number" 
              min={1} 
              max={totalPages}
              value={currentPage}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                if (!isNaN(val) && val >= 1 && val <= totalPages) setCurrentPage(val);
              }}
              className="w-10 text-center border rounded py-1 text-xs font-bold text-[#6C248C] focus:ring-1 focus:ring-purple-500 outline-none"
            />
            <span className="text-xs text-gray-500">จาก {totalPages}</span>
          </div>

          <PaginationButton onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronRight size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(totalPages)} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronsRight size={16} />} />
        </div>
      </div>
    </div>
  );
};

const PaginationButton: React.FC<{ onClick: () => void, disabled: boolean, icon: React.ReactNode }> = ({ onClick, disabled, icon }) => (
  <button 
    onClick={onClick}
    disabled={disabled}
    className={`p-1.5 rounded-md border transition-all ${
      disabled 
      ? 'text-gray-200 border-gray-100 cursor-not-allowed' 
      : 'text-gray-500 border-gray-200 hover:border-purple-400 hover:text-[#6C248C] hover:bg-purple-50'
    }`}
  >
    {icon}
  </button>
);

export default AssetTable;

import React, { useState } from 'react';
