  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);

  // Lifted States for Filtering and Pagination
  const [filters, setFilters] = useState<Record<string, string>>({});
  const [currentPage, setCurrentPage] = useState(1);

  const handleUpdateAsset = (id: string, newName: string) => {
    setAssets(prev => prev.map(asset => 
      asset.id === id ? { ...asset, Computername: newName } : asset
    ));
  };

  const handleAddAsset = (newAsset: any) => {
    const assetWithId = { ...newAsset, id: `new-${Date.now()}` };
    setAssets(prev => [assetWithId, ...prev]);
    setShowAddModal(false);
