import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { Edit2, Check, X, ChevronLeft, ChevronRight, ChevronsLeft, ChevronsRight } from 'lucide-react';

interface AssetTableProps {
  assets: any[];
  headers: string[];
  filters: Record<string, string>;
  setFilters: React.Dispatch<React.SetStateAction<Record<string, string>>>;
  currentPage: number;
  setCurrentPage: React.Dispatch<React.SetStateAction<number>>;
  onUpdateAsset: (id: string, newName: string) => void;
  loading: boolean;
}

const ITEMS_PER_PAGE = 50;

const AssetTable: React.FC<AssetTableProps> = ({ 
  assets, 
  headers, 
  filters, 
  setFilters, 
  currentPage, 
  setCurrentPage, 
  onUpdateAsset, 
  loading 
}) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  // Auto-reset page when filters change (now watching the prop)
  useEffect(() => {
    setCurrentPage(1);
  }, [filters, setCurrentPage]);

  const handleFilterChange = useCallback((header: string, value: string) => {
    setFilters(prev => ({ ...prev, [header]: value }));
  }, [setFilters]);

  // Performance optimized filtering using useMemo
  const filteredAssets = useMemo(() => {
    const filterEntries = Object.entries(filters).filter(([_, val]) => val !== '');
    if (filterEntries.length === 0) return assets;

    return assets.filter(asset => {
      for (let i = 0; i < filterEntries.length; i++) {
        const [key, val] = filterEntries[i];
        const assetValue = (asset[key] !== null && asset[key] !== undefined ? String(asset[key]) : '').toLowerCase();
        if (!assetValue.includes(val.toLowerCase())) return false;
      }
      return true;
    });
  }, [assets, filters]);

  const totalItems = filteredAssets.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;

  const paginatedAssets = useMemo(() => {
    return filteredAssets.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredAssets, startIndex]);

  const startEdit = (asset: any) => {
    setEditingId(asset.id);
    const key = headers.find(h => h.toLowerCase().includes('computername')) || headers[0];
    setEditValue(asset[key]);
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditValue('');
  };

  const saveEdit = (id: string) => {
    onUpdateAsset(id, editValue);
    setEditingId(null);
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-32 space-y-4 flex-1">
        <div className="w-16 h-16 border-4 border-[#6C248C]/20 border-t-[#6C248C] rounded-full animate-spin"></div>
        <div className="text-center">
          <p className="text-[#6C248C] font-bold text-lg">กำลังประมวลผลข้อมูล...</p>
          <p className="text-gray-400 text-sm">กำลังเตรียมตารางข้อมูลจำนวนมหาศาล</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="overflow-auto relative flex-1 scroll-smooth">
        <table className="w-full text-left border-collapse min-w-max">
          <thead>
            <tr className="bg-gray-100/80 border-b border-gray-200 sticky top-0 z-10 backdrop-blur-md">
              {headers.map((header) => (
                <th key={header} className="px-6 py-4 text-[11px] font-bold text-[#6C248C] uppercase tracking-wider">
                  <div className="flex flex-col gap-2">
                    <span className="truncate">{header}</span>
                    <input 
                      type="text" 
                      placeholder={`กรอง...`}
                      // Controlled input to allow clearing from parent
                      value={filters[header] || ''}
                      onChange={(e) => handleFilterChange(header, e.target.value)}
                      className="w-full px-2 py-1.5 text-[10px] font-normal border border-purple-100 rounded focus:border-purple-500 focus:ring-1 focus:ring-purple-200 outline-none bg-white/80 shadow-sm"
                    />
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {paginatedAssets.length > 0 ? (
              paginatedAssets.map((asset) => (
                <tr key={asset.id} className="hover:bg-purple-50/50 transition-colors duration-75">
                  {headers.map((header) => {
                    const isComputerName = header.toLowerCase().includes('computername');
                    return (
                      <td key={`${asset.id}-${header}`} className="px-6 py-3 text-sm text-gray-700 whitespace-nowrap border-r border-gray-50 last:border-0">
                        {isComputerName && editingId === asset.id ? (
                          <div className="flex items-center gap-2 min-w-[200px]">
                            <input 
                              type="text" 
                              value={editValue} 
                              onChange={(e) => setEditValue(e.target.value)}
                              className="border border-purple-400 rounded px-2 py-1 text-sm focus:outline-none w-full bg-white"
                              autoFocus
                            />
                            <button onClick={() => saveEdit(asset.id)} className="text-green-600 hover:bg-green-100 p-1 rounded transition-colors"><Check size={16} /></button>
                            <button onClick={cancelEdit} className="text-red-500 hover:bg-red-100 p-1 rounded transition-colors"><X size={16} /></button>
                          </div>
                        ) : (
                          <div className="flex items-center justify-between group gap-4 min-h-[24px]">
                            <span className={isComputerName ? 'font-bold text-[#6C248C]' : 'opacity-90'}>
                              {asset[header]}
                            </span>
                            {isComputerName && (
                              <button 
                                onClick={() => startEdit(asset)} 
                                className="opacity-0 group-hover:opacity-100 transition-opacity text-purple-300 hover:text-[#6C248C] p-1"
                              >
                                <Edit2 size={13} />
                              </button>
                            )}
                          </div>
                        )}
                      </td>
                    );
                  })}
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={headers.length} className="px-6 py-20 text-center">
                  <div className="flex flex-col items-center gap-2 text-gray-400">
                    <div className="p-4 bg-gray-50 rounded-full"><X size={32} /></div>
                    <p>ไม่พบข้อมูลที่ตรงกับการกรอง</p>
                    <button 
                      onClick={() => setFilters({})}
                      className="mt-2 text-sm text-[#6C248C] font-medium hover:underline"
                    >
                      ล้างตัวกรองทั้งหมด
                    </button>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="bg-white border-t border-gray-100 px-6 py-3 flex flex-col sm:flex-row items-center justify-between gap-4 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.01)]">
        <div className="text-xs text-gray-400 font-medium">
          แถวที่ <span className="text-[#6C248C]">{totalItems > 0 ? startIndex + 1 : 0}</span> ถึง <span className="text-[#6C248C]">{Math.min(startIndex + ITEMS_PER_PAGE, totalItems)}</span>
          <span className="mx-2">|</span>
          ทั้งหมด <span className="text-[#6C248C] font-bold">{totalItems.toLocaleString()}</span> รายการ
        </div>

        <div className="flex items-center gap-1">
          <PaginationButton onClick={() => setCurrentPage(1)} disabled={currentPage === 1} icon={<ChevronsLeft size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} icon={<ChevronLeft size={16} />} />

          <div className="flex items-center gap-2 bg-purple-50/50 px-3 py-1 rounded-full border border-purple-100 mx-2">
            <span className="text-[10px] uppercase font-bold text-purple-400">Page</span>
            <input 
              type="number" 
              min={1} 
              max={totalPages}
              value={currentPage}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                if (!isNaN(val) && val >= 1 && val <= totalPages) setCurrentPage(val);
              }}
              className="w-10 text-center bg-transparent text-sm font-bold text-[#6C248C] focus:outline-none"
            />
            <span className="text-[10px] uppercase font-bold text-purple-400">of {totalPages}</span>
          </div>

          <PaginationButton onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronRight size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(totalPages)} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronsRight size={16} />} />
        </div>
      </div>
    </div>
  );
};

const PaginationButton: React.FC<{ onClick: () => void, disabled: boolean, icon: React.ReactNode }> = ({ onClick, disabled, icon }) => (
  <button 
    onClick={onClick}
    disabled={disabled}
    className={`p-1.5 rounded-lg border transition-all ${
      disabled 
      ? 'text-gray-200 border-gray-100 opacity-50' 
      : 'text-[#6C248C] border-purple-100 hover:border-purple-400 hover:bg-white shadow-sm'
    }`}
  >
    {icon}
  </button>
);

