import React, { useState, useEffect, useCallback } from 'react';
import { 
  Monitor, 
  LayoutDashboard, 
  PlusCircle, 
  Settings, 
  Search, 
  LogOut, 
  Menu, 
  X, 
  Database, 
  RefreshCw, 
  Bell 
} from 'lucide-react';
import AssetTable from './components/AssetTable';
import AddAssetModal from './components/AddAssetModal';
import { fetchSheetData } from './services/sheetService';

const App: React.FC = () => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [assets, setAssets] = useState<any[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);

  // Lifted States for Filtering and Pagination
  const [filters, setFilters] = useState<Record<string, string>>({});
  const [quickSearch, setQuickSearch] = useState('');
  const [currentPage, setCurrentPage] = useState(1);

  const handleUpdateAsset = (id: string, newName: string) => {
    setAssets(prev => prev.map(asset => 
      asset.id === id ? { ...asset, Computername: newName } : asset
    ));
  };

  const handleAddAsset = (newAsset: any) => {
    const assetWithId = { ...newAsset, id: `new-${Date.now()}` };
    setAssets(prev => [assetWithId, ...prev]);
    setShowAddModal(false);
  };

  // Improved Reset function to clear ALL search fields and go to page 1
  const handleRefresh = useCallback(() => {
    setFilters({}); // Clear all per-column filters
    setQuickSearch(''); // Clear global quick search box
    setCurrentPage(1); // Back to first page
    setRefreshKey(prev => prev + 1); // Trigger data reload
  }, []);

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const { data, headers } = await fetchSheetData();
        setAssets(data);
        setHeaders(headers);
      } catch (error) {
        console.error("Error fetching data:", error);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, [refreshKey]);

  return (
    <div className="flex h-screen overflow-hidden bg-gray-50">
      <aside 
        className={`${
          sidebarOpen ? 'w-72' : 'w-20'
        } transition-all duration-300 bg-[#6C248C] text-white flex flex-col shadow-xl z-20 shrink-0`}
      >
        <div className="p-6 flex items-center justify-between border-b border-purple-500/30">
          <div className={`flex items-center gap-3 overflow-hidden ${!sidebarOpen && 'hidden'}`}>
            <div className="bg-white p-1.5 rounded-lg">
              <Database className="text-[#6C248C] w-6 h-6" />
            </div>
            <span className="font-bold text-lg whitespace-nowrap">PEA Asset</span>
          </div>
          <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-1 hover:bg-purple-700 rounded-md">
            {sidebarOpen ? <X size={20} /> : <Menu size={24} className="mx-auto" />}
          </button>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
          <SidebarItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={false} collapsed={!sidebarOpen} />
          <SidebarItem icon={<Monitor size={20} />} label="ข้อมูลทรัพย์สินคอมพิวเตอร์" active={true} collapsed={!sidebarOpen} />
          <SidebarItem icon={<Settings size={20} />} label="Settings" active={false} collapsed={!sidebarOpen} />
        </nav>

        <div className="p-4 border-t border-purple-500/30">
          <SidebarItem icon={<LogOut size={20} />} label="Logout" active={false} collapsed={!sidebarOpen} />
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden min-w-0">
        <header className="h-16 bg-white border-b flex items-center justify-between px-6 shadow-sm shrink-0">
          <h1 className="text-xl font-semibold text-gray-800 truncate pr-4">จัดการข้อมูลทรัพย์สินตามฐานข้อมูลจริง</h1>
          <div className="flex items-center gap-4 shrink-0">
            <div className="relative">
              <Bell className="text-gray-500 cursor-pointer hover:text-purple-700" size={20} />
              <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] rounded-full w-4 h-4 flex items-center justify-center">3</span>
            </div>
            <div className="h-8 w-8 rounded-full bg-purple-100 border border-purple-200 flex items-center justify-center text-[#6C248C] font-bold text-sm cursor-pointer">AD</div>
          </div>
        </header>

        <div className="flex-1 flex flex-col overflow-hidden p-4 space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 shrink-0">
            <StatCard title="Total Assets" value={assets.length} color="bg-purple-600" />
            <StatCard title="Total Columns" value={headers.length} color="bg-blue-500" />
            <StatCard title="Current View" value={assets.length > 0 ? assets.length : 0} color="bg-green-500" />
          </div>

          <div className="flex flex-col sm:flex-row justify-between items-center bg-white p-3 rounded-xl shadow-sm border gap-4 shrink-0">
            <div className="relative w-full sm:w-96">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
              <input 
                type="text" 
                value={quickSearch}
                placeholder="ค้นหาข้อมูลด่วน..." 
                onChange={(e) => {
                  const val = e.target.value;
                  setQuickSearch(val);
                  if (headers.length > 0) {
                    setFilters(prev => ({ ...prev, [headers[0]]: val }));
                  }
                }}
                className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-purple-500 transition-all text-sm"
              />
            </div>
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <button 
                onClick={handleRefresh}
                title="รีเฟรชและล้างการค้นหาทั้งหมด"
                className="p-2 text-[#6C248C] hover:bg-purple-50 rounded-lg border border-purple-100 transition-all flex items-center gap-2 group"
              >
                <RefreshCw size={18} className={`${loading ? 'animate-spin' : 'group-hover:rotate-180'} transition-transform duration-500`} />
                <span className="text-xs font-medium hidden md:inline">ล้างตัวกรองและรีโหลดข้อมูล</span>
              </button>
              <button 
                onClick={() => setShowAddModal(true)}
                className="flex items-center justify-center gap-2 bg-[#6C248C] hover:bg-[#5a1e75] text-white px-5 py-2 rounded-lg text-sm font-medium shadow-md transition-all w-full sm:w-auto"
              >
                <PlusCircle size={18} />
                <span>เพิ่มข้อมูล</span>
              </button>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-md border overflow-hidden flex flex-col flex-1 min-h-0">
            <AssetTable 
              assets={assets} 
              headers={headers}
              filters={filters}
              setFilters={setFilters}
              currentPage={currentPage}
              setCurrentPage={setCurrentPage}
              onUpdateAsset={handleUpdateAsset} 
              loading={loading}
            />
          </div>
        </div>
      </main>

      {showAddModal && (
        <AddAssetModal 
          headers={headers}
          onClose={() => setShowAddModal(false)} 
          onSubmit={handleAddAsset} 
        />
      )}
    </div>
  );
};

const SidebarItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, collapsed: boolean }> = ({ icon, label, active, collapsed }) => (
  <div className={`flex items-center gap-4 px-4 py-3 rounded-lg cursor-pointer transition-all ${
    active ? 'bg-white/20 text-white font-semibold' : 'text-purple-100 hover:bg-white/10 hover:text-white'
