const SHEET_ID = '167-YuqtIFXnHct4JjQt4Rq7NHbLz9ICMaCeo09XhFjA';
const GID = '947966555';
// Use JSON output for much faster native parsing in JavaScript
// Added gid parameter to ensure we fetch data from the specific sheet requested
const JSON_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:json&gid=${GID}`;

export const fetchSheetData = async (): Promise<{data: any[], headers: string[]}> => {
  try {
    const response = await fetch(JSON_URL);
    if (!response.ok) throw new Error('Network response was not ok');

    const text = await response.text();

    // The Google Visualization API returns a string wrapped in a function call:
    // google.visualization.Query.setResponse({...})
    // We need to extract the JSON object inside the parentheses
    const jsonStr = text.substring(text.indexOf('{'), text.lastIndexOf('}') + 1);
    const jsonObj = JSON.parse(jsonStr);

    if (!jsonObj.table || !jsonObj.table.cols || !jsonObj.table.rows) {
      return { data: [], headers: [] };
    }

    // Extract headers
    const headers = jsonObj.table.cols.map((col: any) => col.label || col.id);

    // Efficiently map rows to objects
    // Using a simple for-loop for maximum performance with 12,000+ items
    const rows = jsonObj.table.rows;
    const mappedData = new Array(rows.length);

    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];
      const obj: any = { id: `row-${i}` };

      for (let j = 0; j < headers.length; j++) {
        // Handle null values and extract the formatted value 'v' from cell 'c'
        const cell = row.c[j];
        obj[headers[j]] = cell ? (cell.v !== null ? String(cell.v) : '') : '';
      }
      mappedData[i] = obj;
    }

    return { data: mappedData, headers };
  } catch (error) {
    console.error("Fetch Error:", error);
    return { data: [], headers: [] };
  }
};

