payload.text:
สาเหตุที่ยังบันทึกไม่ได้ ส่วนใหญ่เกิดจาก **Google Apps Script** ยังไม่ได้ถูกตั้งค่าหรือ Deploy ให้เป็น Web App หรือ URL ในโค้ด `sheetService.ts` ยังเป็นค่าว่าง (Placeholder) ครับ

เพื่อให้ระบบทำงานได้จริง คุณต้องทำตาม 2 ขั้นตอนนี้ครับ:

### ขั้นตอนที่ 1: ตั้งค่า Google Apps Script (ฝั่ง Google Sheets)
1. เปิดไฟล์ Google Sheets ของคุณ
2. ไปที่เมนู **Extensions (ส่วนขยาย)** > **Apps Script**
3. ลบโค้ดเดิมออกทั้งหมดและวางโค้ดนี้ลงไป (เน้นการใช้ Column 1 และ 5 ตามที่คุณต้องการ):

```javascript
function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName("Computername"); // แผ่นงานที่จะบันทึก
  var data = JSON.parse(e.postData.contents);

  var key1 = data.key1Value; // ค่าจาก Column 1 (Index 0)
  var key2 = data.key2Value; // ค่าจาก Column 5 (Index 4)
  var newName = data.newName;

  var values = sheet.getDataRange().getValues();
  var headers = values[0];

  // ค้นหาตำแหน่งคอลัมน์ "Computername" ในแผ่นงานปลายทาง
  var colIndex = headers.indexOf("Computername");
  if (colIndex === -1) {
    return ContentService.createTextOutput(JSON.stringify({"result":"error", "message":"คอลัมน์ Computername ไม่พบ"}))
           .setMimeType(ContentService.MimeType.JSON);
  }

  // วนลูปหาแถวที่คอลัมน์ 1 และ 5 ตรงกัน (เริ่มแถวที่ 2 คือ index 1)
  for (var i = 1; i < values.length; i++) {
    // เปรียบเทียบค่า (ใช้ String เพื่อความแม่นยำ)
    if (String(values[i][0]) === String(key1) && String(values[i][4]) === String(key2)) {
      sheet.getRange(i + 1, colIndex + 1).setValue(newName);
      return ContentService.createTextOutput(JSON.stringify({"result":"success"}))
             .setMimeType(ContentService.MimeType.JSON);
    }
  }

  return ContentService.createTextOutput(JSON.stringify({"result":"not_found"}))
         .setMimeType(ContentService.MimeType.JSON);
}
```
