const SHEET_ID = '167-YuqtIFXnHct4JjQt4Rq7NHbLz9ICMaCeo09XhFjA';
const FETCH_SHEET_NAME = 'query';
const UPDATE_SHEET_NAME = 'Computername';

// URL for fetching data (Read-only)
const JSON_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:json&sheet=${encodeURIComponent(FETCH_SHEET_NAME)}`;

/**
 * !!! สำคัญ !!! 
 * นำ Web App URL ที่ได้จากขั้นตอน Deploy Apps Script มาวางที่นี่
 */
const APPS_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbw6H0RPl-YOUR-REAL-ID-HERE/exec';

export const fetchSheetData = async (): Promise<{data: any[], headers: string[], rawHeaders: string[]}> => {
  try {
    const response = await fetch(JSON_URL);
    if (!response.ok) throw new Error('Network response was not ok');

    const text = await response.text();
    const jsonStr = text.substring(text.indexOf('{'), text.lastIndexOf('}') + 1);
    const jsonObj = JSON.parse(jsonStr);

    if (!jsonObj.table || !jsonObj.table.cols || !jsonObj.table.rows) {
      return { data: [], headers: [], rawHeaders: [] };
    }

    const rawHeaders = jsonObj.table.cols.map((col: any) => col.label || col.id);
    const rows = jsonObj.table.rows;
    const mappedData = new Array(rows.length);

    for (let i = 0; i < rows.length; i++) {
      const row = rows[i];
      const obj: any = { id: `row-${i}` };

      for (let j = 0; j < rawHeaders.length; j++) {
        const cell = row.c && row.c[j];
        obj[rawHeaders[j]] = cell ? (cell.v !== null ? String(cell.v) : '') : '';
      }
      mappedData[i] = obj;
    }

    return { data: mappedData, headers: rawHeaders, rawHeaders };
  } catch (error) {
    console.error("Fetch Error:", error);
    return { data: [], headers: [], rawHeaders: [] };
  }
};

export const updateAssetOnSheet = async (payload: { 
  key1Value: string, 
  key2Value: string, 
  newName: string 
}): Promise<boolean> => {
  try {
    // เราใช้การส่งผ่าน fetch พร้อมตรวจสอบว่า URL ถูกเปลี่ยนจากค่าเริ่มต้นหรือยัง
    if (APPS_SCRIPT_URL.includes('YOUR-REAL-ID-HERE')) {
      console.error("กรุณาอัปเดต APPS_SCRIPT_URL ด้วย URL ที่ได้จาก Google Apps Script Deployment");
      return false;
    }

    const response = await fetch(APPS_SCRIPT_URL, {
      method: 'POST',
      mode: 'no-cors', // Apps Script ต้องการ no-cors สำหรับการส่งข้ามโดเมนที่ไม่มี OPTIONS preflight
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });

    // ในโหมด no-cors เบราว์เซอร์จะไม่ให้เราอ่าน status แต่ถ้าไม่มี error ขว้างออกมา มักจะส่งสำเร็จ
    return true; 
  } catch (error) {
    console.error("Update Error:", error);
    return false;
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
