    const h1 = rawHeadersRef.current[0];
    const h5 = rawHeadersRef.current[4];

    const val1 = asset[h1];
    const val5 = asset[h5];

    if (!val1 || !val5) {
      alert(`ไม่สามารถระบุแถวได้: ค่าในคอลัมน์ 1 หรือ 5 เป็นค่าว่าง (${h1}: ${val1}, ${h5}: ${val5})`);
      return;
    }

    const success = await updateAssetOnSheet({
      key1Value: val1,
      key2Value: val5,
      newName: newName
    });

    if (success) {
      // อัปเดตเฉพาะแถวที่ Match กันใน UI
      setAssets(prev => prev.map(a => 
        (a[h1] === val1 && a[h5] === val5) 
