เพื่อให้ระบบสามารถระบุแถวและบันทึกข้อมูลกลับไปยัง Google Sheet แผ่นงาน `Computername` ได้อย่างแม่นยำโดยใช้คอลัมน์ที่ 1 และ 4 ตามที่คุณต้องการ ผมได้ปรับปรุงโค้ดดังนี้ครับ:

### สิ่งที่คุณต้องทำเพิ่มเติม (ฝั่ง Google Sheets):
คุณต้องนำโค้ด Apps Script นี้ไปวางใน **Extensions > Apps Script** และ **Deploy เป็น Web App** (เลือก Who has access: **Anyone**) เพื่อให้หน้าเว็บส่งข้อมูลไปบันทึกได้:

```javascript
function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName("Computername"); // แผ่นงานปลายทาง
  var data = JSON.parse(e.postData.contents);

  var key1 = data.key1; // ค่าจาก Column 1 (สินทรัพย์)
  var key2 = data.key2; // ค่าจาก Column 4 (เลขที่ผลิตภัณฑ์)
  var newName = data.newName;

  var values = sheet.getDataRange().getValues();
  var headers = values[0];
  var colCompName = headers.indexOf("Computername");

  for (var i = 1; i < values.length; i++) {
    // ตรวจสอบ Column 1 (index 0) และ Column 4 (index 3)
    if (String(values[i][0]) === String(key1) && String(values[i][3]) === String(key2)) {
      sheet.getRange(i + 1, colCompName + 1).setValue(newName);
      return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
    }
  }
  return ContentService.createTextOutput("Not Found").setMimeType(ContentService.MimeType.TEXT);
}
```

