      >
        <div className="p-6 flex items-center justify-between border-b border-purple-500/30">
          <div className={`flex items-center gap-3 overflow-hidden ${!sidebarOpen && 'hidden'}`}>
            <div className="bg-white p-1.5 rounded-lg">
              <Database className="text-[#6C248C] w-6 h-6" />
            </div>
            <span className="font-bold text-lg whitespace-nowrap">PEA Asset</span>
          </div>
          <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-1 hover:bg-purple-700 rounded-md">
            {sidebarOpen ? <X size={20} /> : <Menu size={24} className="mx-auto" />}
          </button>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
          <SidebarItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={false} collapsed={!sidebarOpen} />
          <SidebarItem icon={<Monitor size={20} />} label="ข้อมูลทรัพย์สินคอมพิวเตอร์" active={true} collapsed={!sidebarOpen} />
          <SidebarItem icon={<Settings size={20} />} label="Settings" active={false} collapsed={!sidebarOpen} />
        </nav>

        <div className="p-4 border-t border-purple-500/30">
          <SidebarItem icon={<LogOut size={20} />} label="Logout" active={false} collapsed={!sidebarOpen} />
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden min-w-0">
        <header className="h-16 bg-white border-b flex items-center justify-between px-6 shadow-sm shrink-0">
          <h1 className="text-xl font-semibold text-gray-800 truncate pr-4">จัดการข้อมูลคอมพิวเตอร์ (Sync: {FETCH_SHEET_NAME} -> {UPDATE_SHEET_NAME})</h1>
          <div className="flex items-center gap-4 shrink-0">
            <div className="relative">
              <Bell className="text-gray-500 cursor-pointer hover:text-purple-700" size={20} />
              <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] rounded-full w-4 h-4 flex items-center justify-center">3</span>
            </div>
            <div className="h-8 w-8 rounded-full bg-purple-100 border border-purple-200 flex items-center justify-center text-[#6C248C] font-bold text-sm cursor-pointer">AD</div>
          </div>
        </header>

        <div className="flex-1 flex flex-col overflow-hidden p-4 space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 shrink-0">
            <StatCard title="จำนวนรายการ" value={assets.length} color="bg-purple-600" />
            <StatCard title="จำนวนคอลัมน์" value={headers.length} color="bg-blue-500" />
