          <div className="flex flex-col sm:flex-row justify-end items-center bg-white p-3 rounded-xl shadow-sm border gap-4 shrink-0">
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <button 
                onClick={handleRefresh}
                className="p-2 text-[#6C248C] hover:bg-purple-50 rounded-lg border border-purple-100 transition-all flex items-center gap-2 group"
              >
                <RefreshCw size={18} className={`${loading ? 'animate-spin' : 'group-hover:rotate-180'} transition-transform duration-500`} />
                <span className="text-xs font-medium hidden md:inline">รีโหลดข้อมูล</span>
              </button>
              <button 
                onClick={() => setShowAddModal(true)}
                className="flex items-center justify-center gap-2 bg-[#6C248C] hover:bg-[#5a1e75] text-white px-5 py-2 rounded-lg text-sm font-medium shadow-md transition-all w-full sm:w-auto"
              >
                <PlusCircle size={18} />
                <span>เพิ่มข้อมูล</span>
              </button>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-md border overflow-hidden flex flex-col flex-1 min-h-0">
            <AssetTable 
              assets={assets} 
              headers={headers}
              filters={filters}
              setFilters={setFilters}
              currentPage={currentPage}
              setCurrentPage={setCurrentPage}
              onUpdateAsset={handleUpdateAsset} 
              loading={loading}
            />
          </div>
        </div>
      </main>

      {showAddModal && (
        <AddAssetModal 
          headers={headers}
          onClose={() => setShowAddModal(false)} 
          onSubmit={handleAddAsset} 
        />
      )}
    </div>
  );
};

