      <main className="flex-1 flex flex-col overflow-hidden min-w-0">
        <header className="h-16 bg-white border-b flex items-center justify-between px-6 shadow-sm shrink-0">
          <h1 className="text-xl font-semibold text-gray-800 truncate pr-4">จัดการข้อมูลคอมพิวเตอร์ (Sync: {FETCH_SHEET_NAME} -> {UPDATE_SHEET_NAME})</h1>
          <div className="flex items-center gap-4 shrink-0">
            <div className="relative">
              <Bell className="text-gray-500 cursor-pointer hover:text-purple-700" size={20} />
              <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] rounded-full w-4 h-4 flex items-center justify-center">3</span>
            </div>
            <div className="h-8 w-8 rounded-full bg-purple-100 border border-purple-200 flex items-center justify-center text-[#6C248C] font-bold text-sm cursor-pointer">AD</div>
          </div>
        </header>

        <div className="flex-1 flex flex-col overflow-hidden p-4 space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 shrink-0">
            <StatCard title="จำนวนรายการ" value={assets.length} color="bg-purple-600" />
            <StatCard title="จำนวนคอลัมน์" value={headers.length} color="bg-blue-500" />
            <StatCard title="คัดกรองแล้ว" value={assets.length} color="bg-green-500" />
          </div>

          <div className="flex flex-col sm:flex-row justify-end items-center bg-white p-3 rounded-xl shadow-sm border gap-4 shrink-0">
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <button 
                onClick={handleRefresh}
                className="p-2 text-[#6C248C] hover:bg-purple-50 rounded-lg border border-purple-100 transition-all flex items-center gap-2 group"
              >
                <RefreshCw size={18} className={`${loading ? 'animate-spin' : 'group-hover:rotate-180'} transition-transform duration-500`} />
                <span className="text-xs font-medium hidden md:inline">รีโหลดข้อมูล</span>
              </button>
              <button 
                onClick={() => setShowAddModal(true)}
                className="flex items-center justify-center gap-2 bg-[#6C248C] hover:bg-[#5a1e75] text-white px-5 py-2 rounded-lg text-sm font-medium shadow-md transition-all w-full sm:w-auto"
              >
                <PlusCircle size={18} />
                <span>เพิ่มข้อมูล</span>
              </button>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-md border overflow-hidden flex flex-col flex-1 min-h-0">
            <AssetTable 
              assets={assets} 
              headers={headers}
              filters={filters}
              setFilters={setFilters}
              currentPage={currentPage}
              setCurrentPage={setCurrentPage}
              onUpdateAsset={handleUpdateAsset} 
              loading={loading}
            />
          </div>
        </div>
      </main>

      {showAddModal && (
        <AddAssetModal 
          headers={headers}
          onClose={() => setShowAddModal(false)} 
          onSubmit={handleAddAsset} 
        />
      )}
    </div>
  );
};

const SidebarItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, collapsed: boolean }> = ({ icon, label, active, collapsed }) => (
  <div className={`flex items-center gap-4 px-4 py-3 rounded-lg cursor-pointer transition-all ${
    active ? 'bg-white/20 text-white font-semibold' : 'text-purple-100 hover:bg-white/10 hover:text-white'
