export default App;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { 
  Edit2, 
  Check, 
  X, 
  ChevronLeft, 
  ChevronRight, 
  ChevronsLeft, 
  ChevronsRight, 
  Loader2, 
  AlertTriangle,
  CheckCircle2,
  Info
} from 'lucide-react';

interface AssetTableProps {
  assets: any[];
  headers: string[];
  filters: Record<string, string>;
  setFilters: React.Dispatch<React.SetStateAction<Record<string, string>>>;
  currentPage: number;
  setCurrentPage: React.Dispatch<React.SetStateAction<number>>;
  onUpdateAsset: (asset: any, newName: string) => Promise<void>;
  loading: boolean;
}

const ITEMS_PER_PAGE = 50;

const AssetTable: React.FC<AssetTableProps> = ({ 
  assets, 
  headers, 
  filters, 
  setFilters, 
  currentPage, 
  setCurrentPage, 
  onUpdateAsset, 
  loading 
}) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [isSaving, setIsSaving] = useState(false);

  // State สำหรับ Confirmation Modal
  const [showConfirm, setShowConfirm] = useState(false);
  const [pendingAsset, setPendingAsset] = useState<any>(null);

  // State สำหรับ Notification
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  useEffect(() => {
    setCurrentPage(1);
  }, [filters, setCurrentPage]);

  // ซ่อนการแจ้งเตือนอัตโนมัติ
  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  const handleFilterChange = useCallback((header: string, value: string) => {
    setFilters(prev => ({ ...prev, [header]: value }));
  }, [setFilters]);

  const filteredAssets = useMemo(() => {
    const filterEntries = Object.entries(filters).filter(([_, val]) => val !== '') as [string, string][];
    if (filterEntries.length === 0) return assets;

    return assets.filter(asset => {
      for (let i = 0; i < filterEntries.length; i++) {
        const [key, val] = filterEntries[i];
        const rawValue = asset[key];
        const assetValue = (rawValue !== null && rawValue !== undefined ? String(rawValue) : '').toLowerCase();
        const searchStr = typeof val === 'string' ? val.toLowerCase() : String(val).toLowerCase();
        if (!assetValue.includes(searchStr)) return false;
      }
      return true;
    });
  }, [assets, filters]);

  const totalItems = filteredAssets.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;

  const paginatedAssets = useMemo(() => {
    return filteredAssets.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredAssets, startIndex]);

  const startEdit = (asset: any) => {
    setEditingId(asset.id);
    setEditValue(asset["Computername"] || '');
  };

  const cancelEdit = () => {
    if (isSaving) return;
    setEditingId(null);
    setEditValue('');
  };

  const requestSave = (asset: any) => {
    if (editValue.trim() === asset["Computername"]) {
      setEditingId(null);
      return;
    }
    setPendingAsset(asset);
    setShowConfirm(true);
  };

  const confirmSave = async () => {
    if (!pendingAsset) return;
    setIsSaving(true);
    setShowConfirm(false);
    try {
      await onUpdateAsset(pendingAsset, editValue);
      setNotification({ message: 'บันทึกข้อมูลเรียบร้อยแล้ว', type: 'success' });
      setEditingId(null);
    } catch (error) {
      setNotification({ message: 'เกิดข้อผิดพลาดในการบันทึกข้อมูล', type: 'error' });
      console.error(error);
    } finally {
      setIsSaving(false);
      setPendingAsset(null);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-32 space-y-4 flex-1">
        <div className="w-16 h-16 border-4 border-[#6C248C]/20 border-t-[#6C248C] rounded-full animate-spin"></div>
        <div className="text-center">
          <p className="text-[#6C248C] font-bold text-lg">กำลังประมวลผลข้อมูล...</p>
          <p className="text-gray-400 text-sm">กรุณารอสักครู่ ระบบกำลังดึงฐานข้อมูลจริง</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white relative">
      {/* Notification Toast */}
      {notification && (
        <div className={`fixed top-20 right-6 z-[60] flex items-center gap-3 px-6 py-3 rounded-xl shadow-2xl border transition-all animate-in slide-in-from-right-full ${
          notification.type === 'success' ? 'bg-green-50 border-green-200 text-green-800' : 'bg-red-50 border-red-200 text-red-800'
        }`}>
          {notification.type === 'success' ? <CheckCircle2 size={20} /> : <AlertTriangle size={20} />}
          <span className="font-semibold text-sm">{notification.message}</span>
        </div>
      )}

      <div className="overflow-auto relative flex-1 scroll-smooth">
        <table className="w-full text-left border-collapse table-auto min-w-full">
          <thead>
            <tr className="bg-gray-100/90 border-b border-gray-200 sticky top-0 z-10 backdrop-blur-md">
              {headers.map((header) => (
                <th key={header} className="px-4 py-3 text-[11px] font-bold text-[#6C248C] uppercase tracking-wider whitespace-nowrap">
                  <div className="flex flex-col gap-2 min-w-[120px]">
                    <span>{header}</span>
                    <input 
                      type="text" 
                      placeholder={`ค้นหา ${header}`}
                      value={filters[header] || ''}
                      onChange={(e) => handleFilterChange(header, e.target.value)}
                      className="w-full px-2 py-1.5 text-[10px] font-normal border border-purple-100 rounded focus:border-purple-500 focus:ring-1 focus:ring-purple-200 outline-none bg-white/80 shadow-sm transition-all"
                    />
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {paginatedAssets.length > 0 ? (
              paginatedAssets.map((asset) => (
                <tr key={asset.id} className="hover:bg-purple-50/50 transition-colors duration-75">
                  {headers.map((header) => {
                    const isComputerName = header === 'Computername';
                    return (
                      <td key={`${asset.id}-${header}`} className="px-4 py-2.5 text-sm text-gray-700 whitespace-nowrap border-r border-gray-50 last:border-0">
                        {isComputerName && editingId === asset.id ? (
                          <div className="flex items-center gap-2">
                            <input 
                              type="text" 
                              value={editValue} 
                              onChange={(e) => setEditValue(e.target.value)}
                              disabled={isSaving}
                              className={`border border-purple-400 rounded px-2 py-1 text-sm focus:outline-none bg-white min-w-[180px] ${isSaving ? 'opacity-50 cursor-not-allowed' : ''}`}
                              autoFocus
                              onKeyDown={(e) => {
                                if (e.key === 'Enter') requestSave(asset);
                                if (e.key === 'Escape') cancelEdit();
                              }}
                            />
                            <div className="flex items-center gap-1 shrink-0">
                              <button 
                                onClick={() => requestSave(asset)} 
                                disabled={isSaving}
                                className="text-green-600 hover:bg-green-100 p-1 rounded transition-colors disabled:opacity-50" 
                                title="บันทึก"
                              >
                                {isSaving ? <Loader2 size={16} className="animate-spin" /> : <Check size={16} />}
                              </button>
                              <button 
                                onClick={cancelEdit} 
                                disabled={isSaving}
                                className="text-red-500 hover:bg-red-100 p-1 rounded transition-colors disabled:opacity-50" 
                                title="ยกเลิก"
                              >
                                <X size={16} />
                              </button>
                            </div>
                          </div>
                        ) : (
                          <div className="flex items-center justify-between group gap-4 min-h-[24px]">
                            <span className={isComputerName ? 'font-bold text-[#6C248C]' : 'opacity-90'}>
                              {asset[header]}
                            </span>
                            {isComputerName && (
                              <button 
                                onClick={() => startEdit(asset)} 
                                className="opacity-0 group-hover:opacity-100 transition-opacity text-purple-300 hover:text-[#6C248C] p-1 shrink-0"
                                title="แก้ไขชื่อคอมพิวเตอร์"
                              >
                                <Edit2 size={13} />
                              </button>
                            )}
                          </div>
                        )}
                      </td>
                    );
                  })}
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={headers.length} className="px-6 py-20 text-center">
                  <div className="flex flex-col items-center gap-2 text-gray-400">
                    <div className="p-4 bg-gray-50 rounded-full"><X size={32} /></div>
                    <p>ไม่พบข้อมูลที่ตรงกับการกรอง</p>
                    <button 
                      onClick={() => setFilters({})}
                      className="mt-2 text-sm text-[#6C248C] font-medium hover:underline"
                    >
                      ล้างตัวกรองทั้งหมด
                    </button>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <div className="bg-white border-t border-gray-100 px-6 py-3 flex flex-col sm:flex-row items-center justify-between gap-4 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.01)]">
        <div className="text-xs text-gray-400 font-medium whitespace-nowrap">
          แถวที่ <span className="text-[#6C248C]">{totalItems > 0 ? startIndex + 1 : 0}</span> ถึง <span className="text-[#6C248C]">{Math.min(startIndex + ITEMS_PER_PAGE, totalItems)}</span>
          <span className="mx-2">|</span>
          ทั้งหมด <span className="text-[#6C248C] font-bold">{totalItems.toLocaleString()}</span> รายการ
        </div>

        <div className="flex items-center gap-1">
          <PaginationButton onClick={() => setCurrentPage(1)} disabled={currentPage === 1} icon={<ChevronsLeft size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} icon={<ChevronLeft size={16} />} />

          <div className="flex items-center gap-2 bg-purple-50/50 px-3 py-1 rounded-full border border-purple-100 mx-2">
            <span className="text-[10px] uppercase font-bold text-purple-400">Page</span>
            <input 
              type="number" 
              min={1} 
              max={totalPages}
              value={currentPage}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                if (!isNaN(val) && val >= 1 && val <= totalPages) setCurrentPage(val);
              }}
              className="w-10 text-center bg-transparent text-sm font-bold text-[#6C248C] focus:outline-none"
            />
            <span className="text-[10px] uppercase font-bold text-purple-400">of {totalPages}</span>
          </div>

          <PaginationButton onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronRight size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(totalPages)} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronsRight size={16} />} />
        </div>
      </div>

      {/* Confirmation Modal */}
      {showConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="bg-amber-500 px-6 py-4 flex items-center gap-3 text-white">
              <AlertTriangle size={24} />
              <h3 className="text-lg font-bold">ยืนยันการแก้ไขข้อมูล</h3>
            </div>
            <div className="p-6 space-y-4">
              <div className="bg-gray-50 p-4 rounded-xl space-y-2 border border-gray-100">
                <div className="flex justify-between text-xs font-medium text-gray-500 uppercase">
                  <span>สินทรัพย์ (ID)</span>
                  <span className="text-purple-600">{pendingAsset?.[headers[0]]}</span>
                </div>
                <div className="flex justify-between text-xs font-medium text-gray-500 uppercase">
                  <span>เลขที่ผลิตภัณฑ์</span>
                  <span className="text-purple-600">{pendingAsset?.[headers[3]]}</span>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex items-start gap-3 text-gray-600">
                  <div className="mt-1 text-gray-400"><Info size={16} /></div>
                  <p className="text-sm">คุณกำลังจะเปลี่ยน <strong>Computername</strong> จากเดิมคือ:</p>
                </div>
                <div className="flex items-center gap-4">
                  <div className="flex-1 bg-red-50 p-2 rounded border border-red-100 text-red-700 text-sm line-through truncate">
                    {pendingAsset?.["Computername"] || '-(ว่าง)-'}
                  </div>
                  <ChevronRight className="text-gray-300" />
                  <div className="flex-1 bg-green-50 p-2 rounded border border-green-100 text-green-700 text-sm font-bold truncate">
                    {editValue}
                  </div>
                </div>
              </div>

              <p className="text-xs text-gray-400 italic">การเปลี่ยนแปลงนี้จะถูกบันทึกลง Google Sheet ทันที</p>
            </div>
            <div className="bg-gray-50 px-6 py-4 flex justify-end gap-3">
              <button 
                onClick={() => { setShowConfirm(false); setPendingAsset(null); }}
                className="px-4 py-2 rounded-lg border border-gray-300 text-gray-600 hover:bg-white text-sm font-medium transition-colors"
              >
                ยกเลิก
              </button>
              <button 
                onClick={confirmSave}
                className="px-6 py-2 rounded-lg bg-[#6C248C] text-white hover:bg-[#5a1e75] text-sm font-bold shadow-lg transition-all"
              >
                ยืนยันการเปลี่ยน
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const PaginationButton: React.FC<{ onClick: () => void, disabled: boolean, icon: React.ReactNode }> = ({ onClick, disabled, icon }) => (
  <button 
    onClick={onClick}
    disabled={disabled}
    className={`p-1.5 rounded-lg border transition-all ${
      disabled 
      ? 'text-gray-200 border-gray-100 opacity-50' 
      : 'text-[#6C248C] border-purple-100 hover:border-purple-400 hover:bg-white shadow-sm'
    }`}
  >
    {icon}
  </button>
);

export default AssetTable;

payload.text:
เพื่อให้ระบบสามารถบันทึกข้อมูลลง Google Sheet ได้อย่างสมบูรณ์ ผมได้ปรับปรุงส่วนการเชื่อมต่อระหว่าง Frontend และ Backend (Apps Script) โดยเน้นไปที่การจัดการสถานะการบันทึกข้อมูลและการแจ้งเตือนครับ

### การตั้งค่าที่สำคัญ (ฝั่ง Google Sheet):
คุณต้องนำโค้ด Apps Script นี้ไปใส่ใน **Extensions > Apps Script** ของไฟล์ Google Sheet ของคุณ และ **Deploy เป็น Web App** (เลือก "Anyone" ในหัวข้อ Who has access) แล้วนำ URL ที่ได้มาวางแทนที่ `APPS_SCRIPT_URL` ในไฟล์ `sheetService.ts` ครับ

```javascript
// โค้ดสำหรับ Google Apps Script
function doPost(e) {
  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheet = ss.getSheetByName("Computername"); // แผ่นงานที่ต้องการแก้ไข
  var data = JSON.parse(e.postData.contents);

  var key1 = data.key1; // ค่าจาก Column 1 (สินทรัพย์)
  var key2 = data.key2; // ค่าจาก Column 4 (เลขที่ผลิตภัณฑ์)
  var newName = data.newName;

  var values = sheet.getDataRange().getValues();
  var headers = values[0];
  var colCompNameIndex = headers.indexOf("Computername");

  if (colCompNameIndex === -1) colCompNameIndex = 2; // Default เป็น Column C ถ้าหาหัวไม่เจอ

  for (var i = 1; i < values.length; i++) {
    // ตรวจสอบ Column 1 (index 0) และ Column 4 (index 3)
    if (String(values[i][0]) === String(key1) && String(values[i][3]) === String(key2)) {
      sheet.getRange(i + 1, colCompNameIndex + 1).setValue(newName);
      return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
    }
  }
  return ContentService.createTextOutput("Error: Row not found").setMimeType(ContentService.MimeType.TEXT);
}
```

---

### รายละเอียดการอัปเดตโค้ด:
1.  **`sheetService.ts`**: ปรับปรุงฟังก์ชันการส่งข้อมูลให้รองรับการตรวจสอบ URL และส่ง Payload ที่ถูกต้อง
2.  **`App.tsx`**: ปรับเปลี่ยน `handleUpdateAsset` ให้ส่งค่าสถานะกลับไปยังตารางเพื่อแสดงผลการแจ้งเตือน
3.  **`AssetTable.tsx`**: ปรับปรุงการรับค่าผลลัพธ์จากการบันทึก เพื่อแสดง Notification สีเขียว (สำเร็จ) หรือสีแดง (ล้มเหลว)

