const JSON_URL = `https://docs.google.com/spreadsheets/d/${SHEET_ID}/gviz/tq?tqx=out:json&sheet=${encodeURIComponent(FETCH_SHEET_NAME)}`;

/**
 * !!! ข้อแนะนำ !!! 
 * 1. นำโค้ด Apps Script ไป Deploy ใน Google Sheet
 * 2. คัดลอก Web App URL ที่ได้มาวางในตัวแปรด้านล่างนี้
 */
const APPS_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycby_QpY_Y_Placeholder/exec';

export const fetchSheetData = async (): Promise<{data: any[], headers: string[], rawHeaders: string[]}> => {
  try {
    const response = await fetch(JSON_URL);
    if (!response.ok) throw new Error('Network response was not ok');

    const text = await response.text();
    const jsonStr = text.substring(text.indexOf('{'), text.lastIndexOf('}') + 1);
    const jsonObj = JSON.parse(jsonStr);

    if (!jsonObj.table || !jsonObj.table.cols || !jsonObj.table.rows) {
      return { data: [], headers: [], rawHeaders: [] };
    }

    const rawHeaders = jsonObj.table.cols.map((col: any) => col.label || col.id);
    const rows = jsonObj.table.rows;
    const mappedData = rows.map((row: any, i: number) => {
      const obj: any = { id: `row-${i}` };
      rawHeaders.forEach((header: string, j: number) => {
        const cell = row.c && row.c[j];
        obj[header] = cell ? (cell.v !== null ? String(cell.v) : '') : '';
      });
      return obj;
    });

    return { data: mappedData, headers: rawHeaders, rawHeaders };
  } catch (error) {
    console.error("Fetch Error:", error);
    return { data: [], headers: [], rawHeaders: [] };
  }
};

export const updateAssetOnSheet = async (payload: { key1: string, key2: string, newName: string }): Promise<boolean> => {
  try {
    if (APPS_SCRIPT_URL.includes('Placeholder')) {
      console.error("APPS_SCRIPT_URL ยังไม่ได้ตั้งค่า กรุณา Deploy Apps Script ก่อน");
      // ในระหว่างการพัฒนา เราจะคืนค่า true เพื่อให้ UI อัปเดตได้ (Mock Success)
      // แต่เมื่อใช้งานจริงต้องเปลี่ยน URL ครับ
      return false;
    }

    const response = await fetch(APPS_SCRIPT_URL, {
      method: 'POST',
      mode: 'no-cors', // ใช้ no-cors เพราะ GAS ไม่รองรับ CORS โดยตรงแบบง่าย
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
    });

    // โหมด no-cors จะไม่สามารถอ่าน response status ได้ 
    // แต่ถ้า fetch ไม่ throw error แสดงว่าคำขอถูกส่งออกไปสำเร็จ
    return true; 
  } catch (error) {
    console.error("Update Error:", error);
    return false;
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Monitor, 
  LayoutDashboard, 
  PlusCircle, 
  Settings, 
  LogOut, 
  Menu, 
  X, 
  Database, 
  RefreshCw, 
  Bell 
} from 'lucide-react';
import AssetTable from './components/AssetTable';
import AddAssetModal from './components/AddAssetModal';
import { fetchSheetData, updateAssetOnSheet, FETCH_SHEET_NAME, UPDATE_SHEET_NAME } from './services/sheetService';

