import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { 
  Edit2, 
  Check, 
  X, 
  ChevronLeft, 
  ChevronRight, 
  ChevronsLeft, 
  ChevronsRight, 
  Loader2, 
  AlertTriangle,
  CheckCircle2,
  Info
} from 'lucide-react';

interface AssetTableProps {
  assets: any[];
  headers: string[];
  filters: Record<string, string>;
  setFilters: React.Dispatch<React.SetStateAction<Record<string, string>>>;
  currentPage: number;
  setCurrentPage: React.Dispatch<React.SetStateAction<number>>;
  onUpdateAsset: (asset: any, newName: string) => Promise<boolean>;
  loading: boolean;
}

const ITEMS_PER_PAGE = 50;

const AssetTable: React.FC<AssetTableProps> = ({ 
  assets, 
  headers, 
  filters, 
  setFilters, 
  currentPage, 
  setCurrentPage, 
  onUpdateAsset, 
  loading 
}) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [isSaving, setIsSaving] = useState(false);

  const [showConfirm, setShowConfirm] = useState(false);
  const [pendingAsset, setPendingAsset] = useState<any>(null);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  useEffect(() => {
    setCurrentPage(1);
  }, [filters, setCurrentPage]);

  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  const handleFilterChange = useCallback((header: string, value: string) => {
    setFilters(prev => ({ ...prev, [header]: value }));
  }, [setFilters]);

  const filteredAssets = useMemo(() => {
    const filterEntries = Object.entries(filters).filter(([_, val]) => val !== '') as [string, string][];
    if (filterEntries.length === 0) return assets;

    return assets.filter(asset => {
      for (let i = 0; i < filterEntries.length; i++) {
        const [key, val] = filterEntries[i];
        const rawValue = asset[key];
        const assetValue = (rawValue !== null && rawValue !== undefined ? String(rawValue) : '').toLowerCase();
        const searchStr = typeof val === 'string' ? val.toLowerCase() : String(val).toLowerCase();
        if (!assetValue.includes(searchStr)) return false;
      }
      return true;
    });
  }, [assets, filters]);

  const totalItems = filteredAssets.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;

  const paginatedAssets = useMemo(() => {
    return filteredAssets.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredAssets, startIndex]);

  const startEdit = (asset: any) => {
    setEditingId(asset.id);
    setEditValue(asset["Computername"] || '');
  };

  const cancelEdit = () => {
    if (isSaving) return;
    setEditingId(null);
    setEditValue('');
  };

  const requestSave = (asset: any) => {
    if (editValue.trim() === asset["Computername"]) {
      setEditingId(null);
      return;
    }
    setPendingAsset(asset);
    setShowConfirm(true);
  };

  const confirmSave = async () => {
    if (!pendingAsset) return;
    setIsSaving(true);
    setShowConfirm(false);

    try {
      const success = await onUpdateAsset(pendingAsset, editValue);
      if (success) {
        setNotification({ message: 'บันทึกข้อมูลเรียบร้อยแล้ว', type: 'success' });
        setEditingId(null);
      } else {
        setNotification({ message: 'ไม่สามารถเชื่อมต่อเซิร์ฟเวอร์ได้ กรุณาตรวจสอบ Apps Script URL', type: 'error' });
      }
    } catch (error) {
      setNotification({ message: 'เกิดข้อผิดพลาดทางเทคนิคในการบันทึกข้อมูล', type: 'error' });
      console.error(error);
    } finally {
      setIsSaving(false);
      setPendingAsset(null);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-32 space-y-4 flex-1">
        <div className="w-16 h-16 border-4 border-[#6C248C]/20 border-t-[#6C248C] rounded-full animate-spin"></div>
        <div className="text-center">
          <p className="text-[#6C248C] font-bold text-lg">กำลังประมวลผลข้อมูล...</p>
          <p className="text-gray-400 text-sm">กรุณารอสักครู่ ระบบกำลังดึงฐานข้อมูลจริง</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white relative">
      {/* Notification Toast */}
      {notification && (
        <div className={`fixed top-20 right-6 z-[60] flex items-center gap-3 px-6 py-3 rounded-xl shadow-2xl border transition-all animate-in slide-in-from-right-full duration-300 ${
          notification.type === 'success' ? 'bg-green-50 border-green-200 text-green-800' : 'bg-red-50 border-red-200 text-red-800'
        }`}>
          {notification.type === 'success' ? <CheckCircle2 size={20} className="text-green-500" /> : <AlertTriangle size={20} className="text-red-500" />}
          <span className="font-semibold text-sm">{notification.message}</span>
          <button onClick={() => setNotification(null)} className="ml-2 hover:opacity-70"><X size={14} /></button>
        </div>
      )}

      <div className="overflow-auto relative flex-1 scroll-smooth">
        <table className="w-full text-left border-collapse table-auto min-w-full">
          <thead>
            <tr className="bg-gray-100/90 border-b border-gray-200 sticky top-0 z-10 backdrop-blur-md">
              {headers.map((header) => (
                <th key={header} className="px-4 py-3 text-[11px] font-bold text-[#6C248C] uppercase tracking-wider whitespace-nowrap">
                  <div className="flex flex-col gap-2 min-w-[120px]">
                    <span>{header}</span>
                    <input 
                      type="text" 
                      placeholder={`ค้นหา ${header}`}
                      value={filters[header] || ''}
                      onChange={(e) => handleFilterChange(header, e.target.value)}
                      className="w-full px-2 py-1.5 text-[10px] font-normal border border-purple-100 rounded focus:border-purple-500 focus:ring-1 focus:ring-purple-200 outline-none bg-white/80 shadow-sm transition-all"
                    />
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {paginatedAssets.length > 0 ? (
              paginatedAssets.map((asset) => (
                <tr key={asset.id} className="hover:bg-purple-50/50 transition-colors duration-75">
                  {headers.map((header) => {
                    const isComputerName = header === 'Computername';
                    return (
                      <td key={`${asset.id}-${header}`} className="px-4 py-2.5 text-sm text-gray-700 whitespace-nowrap border-r border-gray-50 last:border-0">
                        {isComputerName && editingId === asset.id ? (
                          <div className="flex items-center gap-2">
                            <input 
                              type="text" 
                              value={editValue} 
                              onChange={(e) => setEditValue(e.target.value)}
                              disabled={isSaving}
                              className={`border border-purple-400 rounded px-2 py-1 text-sm focus:outline-none bg-white min-w-[180px] shadow-sm ${isSaving ? 'opacity-50 cursor-not-allowed' : ''}`}
                              autoFocus
                              onKeyDown={(e) => {
                                if (e.key === 'Enter') requestSave(asset);
                                if (e.key === 'Escape') cancelEdit();
                              }}
                            />
                            <div className="flex items-center gap-1 shrink-0">
                              <button 
                                onClick={() => requestSave(asset)} 
                                disabled={isSaving}
                                className="text-green-600 hover:bg-green-100 p-1 rounded transition-colors disabled:opacity-50" 
                                title="บันทึก"
                              >
                                {isSaving ? <Loader2 size={16} className="animate-spin text-purple-600" /> : <Check size={16} />}
                              </button>
                              <button 
                                onClick={cancelEdit} 
                                disabled={isSaving}
                                className="text-red-500 hover:bg-red-100 p-1 rounded transition-colors disabled:opacity-50" 
                                title="ยกเลิก"
                              >
                                <X size={16} />
                              </button>
                            </div>
                          </div>
                        ) : (
                          <div className="flex items-center justify-between group gap-4 min-h-[24px]">
                            <span className={isComputerName ? 'font-bold text-[#6C248C]' : 'opacity-90'}>
                              {asset[header] || '-'}
                            </span>
                            {isComputerName && (
                              <button 
                                onClick={() => startEdit(asset)} 
                                className="opacity-0 group-hover:opacity-100 transition-opacity text-purple-300 hover:text-[#6C248C] p-1 shrink-0 bg-purple-50 rounded"
                                title="แก้ไขชื่อคอมพิวเตอร์"
                              >
                                <Edit2 size={13} />
                              </button>
                            )}
                          </div>
                        )}
                      </td>
                    );
                  })}
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={headers.length} className="px-6 py-20 text-center">
                  <div className="flex flex-col items-center gap-2 text-gray-400">
                    <div className="p-4 bg-gray-50 rounded-full"><X size={32} /></div>
                    <p>ไม่พบข้อมูลที่ตรงกับการกรอง</p>
                    <button 
                      onClick={() => setFilters({})}
                      className="mt-2 text-sm text-[#6C248C] font-medium hover:underline"
                    >
                      ล้างตัวกรองทั้งหมด
                    </button>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination Footer */}
      <div className="bg-white border-t border-gray-100 px-6 py-3 flex flex-col sm:flex-row items-center justify-between gap-4 z-20 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.01)]">
        <div className="text-xs text-gray-400 font-medium whitespace-nowrap">
          แถวที่ <span className="text-[#6C248C]">{totalItems > 0 ? startIndex + 1 : 0}</span> ถึง <span className="text-[#6C248C]">{Math.min(startIndex + ITEMS_PER_PAGE, totalItems)}</span>
          <span className="mx-2">|</span>
          ทั้งหมด <span className="text-[#6C248C] font-bold">{totalItems.toLocaleString()}</span> รายการ
        </div>

        <div className="flex items-center gap-1">
          <PaginationButton onClick={() => setCurrentPage(1)} disabled={currentPage === 1} icon={<ChevronsLeft size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} icon={<ChevronLeft size={16} />} />

          <div className="flex items-center gap-2 bg-purple-50/50 px-3 py-1 rounded-full border border-purple-100 mx-2">
            <span className="text-[10px] uppercase font-bold text-purple-400">Page</span>
            <input 
              type="number" 
              min={1} 
              max={totalPages}
              value={currentPage}
              onChange={(e) => {
                const val = parseInt(e.target.value);
                if (!isNaN(val) && val >= 1 && val <= totalPages) setCurrentPage(val);
              }}
              className="w-10 text-center bg-transparent text-sm font-bold text-[#6C248C] focus:outline-none"
            />
            <span className="text-[10px] uppercase font-bold text-purple-400">of {totalPages}</span>
          </div>

          <PaginationButton onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronRight size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(totalPages)} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronsRight size={16} />} />
        </div>
      </div>

      {/* Confirmation Modal */}
      {showConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="bg-amber-500 px-6 py-4 flex items-center gap-3 text-white">
              <AlertTriangle size={24} />
              <h3 className="text-lg font-bold">ยืนยันการแก้ไขข้อมูล</h3>
            </div>
            <div className="p-6 space-y-4">
              <div className="bg-gray-50 p-4 rounded-xl space-y-2 border border-gray-100">
                <div className="flex justify-between text-xs font-medium text-gray-500 uppercase">
                  <span>สินทรัพย์ (ID)</span>
                  <span className="text-purple-600 font-bold">{pendingAsset?.[headers[0]]}</span>
                </div>
                <div className="flex justify-between text-xs font-medium text-gray-500 uppercase">
                  <span>เลขที่ผลิตภัณฑ์</span>
                  <span className="text-purple-600 font-bold">{pendingAsset?.[headers[3]]}</span>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex items-start gap-3 text-gray-600">
                  <div className="mt-1 text-gray-400"><Info size={16} /></div>
                  <p className="text-sm">คุณกำลังจะเปลี่ยน <strong>Computername</strong> จากเดิมคือ:</p>
                </div>
                <div className="flex items-center gap-4">
                  <div className="flex-1 bg-red-50 p-2 rounded border border-red-100 text-red-700 text-sm line-through truncate">
                    {pendingAsset?.["Computername"] || '-(ว่าง)-'}
                  </div>
                  <ChevronRight className="text-gray-300" />
                  <div className="flex-1 bg-green-50 p-2 rounded border border-green-100 text-green-700 text-sm font-bold truncate">
                    {editValue}
                  </div>
                </div>
              </div>

              <p className="text-xs text-gray-400 italic">การเปลี่ยนแปลงนี้จะถูกบันทึกลง Google Sheet ทันที</p>
            </div>
            <div className="bg-gray-50 px-6 py-4 flex justify-end gap-3">
              <button 
                onClick={() => { setShowConfirm(false); setPendingAsset(null); }}
                className="px-4 py-2 rounded-lg border border-gray-300 text-gray-600 hover:bg-white text-sm font-medium transition-colors"
              >
                ยกเลิก
              </button>
              <button 
                onClick={confirmSave}
                className="px-6 py-2 rounded-lg bg-[#6C248C] text-white hover:bg-[#5a1e75] text-sm font-bold shadow-lg transition-all"
              >
                ยืนยันการเปลี่ยน
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const PaginationButton: React.FC<{ onClick: () => void, disabled: boolean, icon: React.ReactNode }> = ({ onClick, disabled, icon }) => (
  <button 
    onClick={onClick}
    disabled={disabled}
    className={`p-1.5 rounded-lg border transition-all ${
      disabled 
      ? 'text-gray-200 border-gray-100 opacity-50' 
      : 'text-[#6C248C] border-purple-100 hover:border-purple-400 hover:bg-white shadow-sm'
    }`}
  >
    {icon}
  </button>
);

export default AssetTable;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { 
  Edit2, 
  Check, 
  X, 
  ChevronLeft, 
  ChevronRight, 
  ChevronsLeft, 
  ChevronsRight, 
  Loader2, 
  AlertTriangle,
  CheckCircle2,
  Info,
  Hash
} from 'lucide-react';

interface AssetTableProps {
  assets: any[];
  headers: string[];
  filters: Record<string, string>;
  setFilters: React.Dispatch<React.SetStateAction<Record<string, string>>>;
  currentPage: number;
  setCurrentPage: React.Dispatch<React.SetStateAction<number>>;
  onUpdateAsset: (asset: any, newName: string) => Promise<boolean>;
  loading: boolean;
}

const ITEMS_PER_PAGE = 50;

const AssetTable: React.FC<AssetTableProps> = ({ 
  assets, 
  headers, 
  filters, 
  setFilters, 
  currentPage, 
  setCurrentPage, 
  onUpdateAsset, 
  loading 
}) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [isSaving, setIsSaving] = useState(false);

  const [showConfirm, setShowConfirm] = useState(false);
  const [pendingAsset, setPendingAsset] = useState<any>(null);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  useEffect(() => {
    setCurrentPage(1);
  }, [filters, setCurrentPage]);

  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 4000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  const handleFilterChange = useCallback((header: string, value: string) => {
    setFilters(prev => ({ ...prev, [header]: value }));
  }, [setFilters]);

  const filteredAssets = useMemo(() => {
    const filterEntries = Object.entries(filters).filter(([_, val]) => val !== '') as [string, string][];
    if (filterEntries.length === 0) return assets;

    return assets.filter(asset => {
      for (let i = 0; i < filterEntries.length; i++) {
        const [key, val] = filterEntries[i];
        const rawValue = asset[key];
        const assetValue = (rawValue !== null && rawValue !== undefined ? String(rawValue) : '').toLowerCase();
        const searchStr = typeof val === 'string' ? val.toLowerCase() : String(val).toLowerCase();
        if (!assetValue.includes(searchStr)) return false;
      }
      return true;
    });
  }, [assets, filters]);

  const totalItems = filteredAssets.length;
  const totalPages = Math.ceil(totalItems / ITEMS_PER_PAGE);
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;

  const paginatedAssets = useMemo(() => {
    return filteredAssets.slice(startIndex, startIndex + ITEMS_PER_PAGE);
  }, [filteredAssets, startIndex]);

  const startEdit = (asset: any) => {
    setEditingId(asset.id);
    setEditValue(asset["Computername"] || '');
  };

  const cancelEdit = () => {
    if (isSaving) return;
    setEditingId(null);
    setEditValue('');
  };

  const requestSave = (asset: any) => {
    if (editValue.trim() === asset["Computername"]) {
      setEditingId(null);
      return;
    }
    setPendingAsset(asset);
    setShowConfirm(true);
  };

  const confirmSave = async () => {
    if (!pendingAsset) return;
    setIsSaving(true);
    setShowConfirm(false);

    try {
      const success = await onUpdateAsset(pendingAsset, editValue);
      if (success) {
        setNotification({ message: 'บันทึกข้อมูลเรียบร้อยแล้ว', type: 'success' });
        setEditingId(null);
      } else {
        setNotification({ message: 'ไม่สามารถเชื่อมต่อเซิร์ฟเวอร์ได้ กรุณาตรวจสอบ Apps Script URL', type: 'error' });
      }
    } catch (error) {
      setNotification({ message: 'เกิดข้อผิดพลาดทางเทคนิคในการบันทึกข้อมูล', type: 'error' });
      console.error(error);
    } finally {
      setIsSaving(false);
      setPendingAsset(null);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-32 space-y-4 flex-1">
        <div className="w-16 h-16 border-4 border-[#6C248C]/20 border-t-[#6C248C] rounded-full animate-spin"></div>
        <div className="text-center">
          <p className="text-[#6C248C] font-bold text-lg">กำลังประมวลผลข้อมูล...</p>
          <p className="text-gray-400 text-sm">กรุณารอสักครู่ ระบบกำลังดึงฐานข้อมูลจริง</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white relative">
      {notification && (
        <div className={`fixed top-20 right-6 z-[60] flex items-center gap-3 px-6 py-3 rounded-xl shadow-2xl border transition-all animate-in slide-in-from-right-full duration-300 ${
          notification.type === 'success' ? 'bg-green-50 border-green-200 text-green-800' : 'bg-red-50 border-red-200 text-red-800'
        }`}>
          {notification.type === 'success' ? <CheckCircle2 size={20} className="text-green-500" /> : <AlertTriangle size={20} className="text-red-500" />}
          <span className="font-semibold text-sm">{notification.message}</span>
          <button onClick={() => setNotification(null)} className="ml-2 hover:opacity-70"><X size={14} /></button>
        </div>
      )}

      <div className="overflow-auto relative flex-1 scroll-smooth">
        <table className="w-full text-left border-collapse table-auto min-w-full">
          <thead>
            <tr className="bg-gray-100/90 border-b border-gray-200 sticky top-0 z-10 backdrop-blur-md">
              {headers.map((header) => (
                <th key={header} className="px-4 py-3 text-[11px] font-bold text-[#6C248C] uppercase tracking-wider whitespace-nowrap">
                  <div className="flex flex-col gap-2 min-w-[120px]">
                    <span>{header}</span>
                    <input 
                      type="text" 
                      placeholder={`ค้นหา ${header}`}
                      value={filters[header] || ''}
                      onChange={(e) => handleFilterChange(header, e.target.value)}
                      className="w-full px-2 py-1.5 text-[10px] font-normal border border-purple-100 rounded focus:border-purple-500 focus:ring-1 focus:ring-purple-200 outline-none bg-white/80 shadow-sm transition-all"
                    />
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {paginatedAssets.map((asset) => (
              <tr key={asset.id} className="hover:bg-purple-50/50 transition-colors duration-75">
                {headers.map((header) => {
                  const isComputerName = header === 'Computername';
                  return (
                    <td key={`${asset.id}-${header}`} className="px-4 py-2.5 text-sm text-gray-700 whitespace-nowrap border-r border-gray-50 last:border-0">
                      {isComputerName && editingId === asset.id ? (
                        <div className="flex items-center gap-2">
                          <input 
                            type="text" 
                            value={editValue} 
                            onChange={(e) => setEditValue(e.target.value)}
                            disabled={isSaving}
                            className={`border border-purple-400 rounded px-2 py-1 text-sm focus:outline-none bg-white min-w-[180px] shadow-sm ${isSaving ? 'opacity-50 cursor-not-allowed' : ''}`}
                            autoFocus
                            onKeyDown={(e) => {
                              if (e.key === 'Enter') requestSave(asset);
                              if (e.key === 'Escape') cancelEdit();
                            }}
                          />
                          <div className="flex items-center gap-1 shrink-0">
                            <button onClick={() => requestSave(asset)} disabled={isSaving} className="text-green-600 hover:bg-green-100 p-1 rounded disabled:opacity-50"><Check size={16} /></button>
                            <button onClick={cancelEdit} disabled={isSaving} className="text-red-500 hover:bg-red-100 p-1 rounded disabled:opacity-50"><X size={16} /></button>
                          </div>
                        </div>
                      ) : (
                        <div className="flex items-center justify-between group gap-4 min-h-[24px]">
                          <span className={isComputerName ? 'font-bold text-[#6C248C]' : 'opacity-90'}>{asset[header] || '-'}</span>
                          {isComputerName && (
                            <button onClick={() => startEdit(asset)} className="opacity-0 group-hover:opacity-100 transition-opacity text-purple-300 hover:text-[#6C248C] p-1 bg-purple-50 rounded"><Edit2 size={13} /></button>
                          )}
                        </div>
                      )}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="bg-white border-t border-gray-100 px-6 py-3 flex flex-col sm:flex-row items-center justify-between gap-4 z-20 shadow-sm">
        <div className="text-xs text-gray-400 font-medium">
          แถวที่ <span className="text-[#6C248C]">{totalItems > 0 ? startIndex + 1 : 0}</span> ถึง <span className="text-[#6C248C]">{Math.min(startIndex + ITEMS_PER_PAGE, totalItems)}</span> ทั้งหมด <span className="text-[#6C248C] font-bold">{totalItems.toLocaleString()}</span> รายการ
        </div>
        <div className="flex items-center gap-1">
          <PaginationButton onClick={() => setCurrentPage(1)} disabled={currentPage === 1} icon={<ChevronsLeft size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))} disabled={currentPage === 1} icon={<ChevronLeft size={16} />} />
          <div className="flex items-center gap-2 bg-purple-50/50 px-3 py-1 rounded-full border border-purple-100 mx-2">
            <span className="text-[10px] uppercase font-bold text-purple-400">Page</span>
            <span className="text-sm font-bold text-[#6C248C]">{currentPage}</span>
            <span className="text-[10px] uppercase font-bold text-purple-400">of {totalPages}</span>
          </div>
          <PaginationButton onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronRight size={16} />} />
          <PaginationButton onClick={() => setCurrentPage(totalPages)} disabled={currentPage === totalPages || totalPages === 0} icon={<ChevronsRight size={16} />} />
        </div>
      </div>

      {showConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="bg-[#6C248C] px-6 py-4 flex items-center gap-3 text-white">
              <AlertTriangle size={24} />
              <h3 className="text-lg font-bold">ยืนยันการบันทึก (ตรวจสอบพิกัด)</h3>
            </div>
            <div className="p-6 space-y-4">
              <div className="bg-gray-50 p-4 rounded-xl space-y-3 border border-gray-100 shadow-inner">
                <div className="flex items-center gap-2 text-[#6C248C] font-bold text-xs uppercase border-b pb-2 mb-2">
                  <Hash size={14} />
                  <span>Column Identifiers (Coordinates)</span>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <p className="text-[10px] text-gray-400 font-bold uppercase">Index 0 (Col A)</p>
                    <p className="text-xs font-semibold text-gray-700 truncate" title={headers[0]}>{headers[0]}</p>
                    <p className="text-sm font-bold text-[#6C248C] truncate">{pendingAsset?.[headers[0]]}</p>
                  </div>
                  <div className="space-y-1">
                    <p className="text-[10px] text-gray-400 font-bold uppercase">Index 3 (Col D)</p>
                    <p className="text-xs font-semibold text-gray-700 truncate" title={headers[3]}>{headers[3]}</p>
                    <p className="text-sm font-bold text-[#6C248C] truncate">{pendingAsset?.[headers[3]]}</p>
                  </div>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex items-start gap-3 text-gray-600">
                  <div className="mt-1 text-gray-400"><Info size={16} /></div>
                  <p className="text-sm">เปลี่ยน <strong>Computername</strong> จากเดิม:</p>
                </div>
                <div className="flex items-center gap-4 bg-gray-50 p-3 rounded-lg border border-dashed border-gray-200">
                  <div className="flex-1 text-red-700 text-xs line-through truncate opacity-50">
                    {pendingAsset?.["Computername"] || '-(ว่าง)-'}
                  </div>
                  <ChevronRight size={14} className="text-gray-300" />
                  <div className="flex-1 text-green-700 text-sm font-bold truncate">
                    {editValue}
                  </div>
                </div>
              </div>
            </div>
            <div className="bg-gray-50 px-6 py-4 flex justify-end gap-3">
              <button onClick={() => { setShowConfirm(false); setPendingAsset(null); }} className="px-4 py-2 rounded-lg border border-gray-300 text-gray-600 hover:bg-white text-sm font-medium">ยกเลิก</button>
              <button onClick={confirmSave} className="px-6 py-2 rounded-lg bg-[#6C248C] text-white hover:bg-[#5a1e75] text-sm font-bold shadow-lg">ยืนยันและส่งพิกัด</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const PaginationButton: React.FC<{ onClick: () => void, disabled: boolean, icon: React.ReactNode }> = ({ onClick, disabled, icon }) => (
  <button onClick={onClick} disabled={disabled} className={`p-1.5 rounded-lg border transition-all ${disabled ? 'text-gray-200 border-gray-100 opacity-50' : 'text-[#6C248C] border-purple-100 hover:border-purple-400 hover:bg-white shadow-sm'}`}>{icon}</button>
);

export default AssetTable;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  Monitor, 
  LayoutDashboard, 
  PlusCircle, 
  Settings, 
  LogOut, 
  Menu, 
  X, 
  Database, 
  RefreshCw, 
  Bell 
} from 'lucide-react';
import AssetTable from './components/AssetTable';
import AddAssetModal from './components/AddAssetModal';
import { fetchSheetData, updateAssetOnSheet, FETCH_SHEET_NAME, UPDATE_SHEET_NAME } from './services/sheetService';

const App: React.FC = () => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [assets, setAssets] = useState<any[]>([]);
  const [headers, setHeaders] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);

  const rawHeadersRef = useRef<string[]>([]);
  const [filters, setFilters] = useState<Record<string, string>>({});
  const [currentPage, setCurrentPage] = useState(1);

  const handleUpdateAsset = async (asset: any, newName: string): Promise<boolean> => {
    // พิกัดคอลัมน์อ้างอิงที่ใช้ส่งไป Apps Script
    const h1Index = 0; // Column A
    const h4Index = 3; // Column D

    const h1 = rawHeadersRef.current[h1Index];
    const h4 = rawHeadersRef.current[h4Index];

    const key1Value = asset[h1];
    const key2Value = asset[h4];

    // Log ตรวจสอบพิกัดและค่าข้อมูล
    console.group("🚀 Debug: Sending Update Coordinates");
    console.log(`Target Sheet: ${UPDATE_SHEET_NAME}`);
    console.log(`Key 1 (Index ${h1Index}): ${h1} -> "${key1Value}"`);
    console.log(`Key 2 (Index ${h4Index}): ${h4} -> "${key2Value}"`);
    console.log(`Update Target: Computername -> "${newName}"`);
    console.groupEnd();

    if (!key1Value || !key2Value) {
      console.warn("Reference keys missing. Check sheet structure.");
      return false;
    }

    const success = await updateAssetOnSheet({
      key1: key1Value,
      key2: key2Value,
      newName: newName
    });

    if (success) {
      setAssets(prev => prev.map(a => 
        (a[h1] === key1Value && a[h4] === key2Value) 
        ? { ...a, Computername: newName } 
        : a
      ));
      return true;
    } else {
      return false;
    }
  };

  const handleAddAsset = (newAsset: any) => {
    const assetWithId = { ...newAsset, id: `new-${Date.now()}` };
    setAssets(prev => [assetWithId, ...prev]);
    setShowAddModal(false);
  };

  const handleRefresh = useCallback(() => {
    setFilters({});
    setCurrentPage(1);
    setRefreshKey(prev => prev + 1);
  }, []);

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const { data, headers: allHeaders, rawHeaders } = await fetchSheetData();
        rawHeadersRef.current = rawHeaders;

        const excludedColumns = ['เลขที่สินค้าคงคลัง', 'ค่าเสื่อมสะสม'];
        const filteredHeaders = allHeaders.filter(header => !excludedColumns.includes(header));

        setAssets(data);
        setHeaders(filteredHeaders);
      } catch (error) {
        console.error("Error fetching data:", error);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, [refreshKey]);

  return (
    <div className="flex h-screen overflow-hidden bg-gray-50">
      <aside className={`${sidebarOpen ? 'w-72' : 'w-20'} transition-all duration-300 bg-[#6C248C] text-white flex flex-col shadow-xl z-20 shrink-0`}>
        <div className="p-6 flex items-center justify-between border-b border-purple-500/30">
          <div className={`flex items-center gap-3 overflow-hidden ${!sidebarOpen && 'hidden'}`}>
            <div className="bg-white p-1.5 rounded-lg"><Database className="text-[#6C248C] w-6 h-6" /></div>
            <span className="font-bold text-lg whitespace-nowrap">PEA Asset</span>
          </div>
          <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-1 hover:bg-purple-700 rounded-md">
            {sidebarOpen ? <X size={20} /> : <Menu size={24} className="mx-auto" />}
          </button>
        </div>
        <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
          <SidebarItem icon={<LayoutDashboard size={20} />} label="Dashboard" active={false} collapsed={!sidebarOpen} />
          <SidebarItem icon={<Monitor size={20} />} label="ข้อมูลทรัพย์สินคอมพิวเตอร์" active={true} collapsed={!sidebarOpen} />
          <SidebarItem icon={<Settings size={20} />} label="Settings" active={false} collapsed={!sidebarOpen} />
        </nav>
        <div className="p-4 border-t border-purple-500/30">
          <SidebarItem icon={<LogOut size={20} />} label="Logout" active={false} collapsed={!sidebarOpen} />
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden min-w-0">
        <header className="h-16 bg-white border-b flex items-center justify-between px-6 shadow-sm shrink-0">
          <h1 className="text-xl font-semibold text-gray-800 truncate pr-4">จัดการข้อมูลคอมพิวเตอร์ (Sync: {FETCH_SHEET_NAME} -> {UPDATE_SHEET_NAME})</h1>
          <div className="flex items-center gap-4 shrink-0">
            <div className="relative">
              <Bell className="text-gray-500 cursor-pointer" size={20} />
              <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] rounded-full w-4 h-4 flex items-center justify-center">3</span>
            </div>
            <div className="h-8 w-8 rounded-full bg-purple-100 border border-purple-200 flex items-center justify-center text-[#6C248C] font-bold text-sm cursor-pointer">AD</div>
          </div>
        </header>

        <div className="flex-1 flex flex-col overflow-hidden p-4 space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 shrink-0">
            <StatCard title="จำนวนรายการ" value={assets.length} color="bg-purple-600" />
            <StatCard title="จำนวนคอลัมน์" value={headers.length} color="bg-blue-500" />
            <StatCard title="คัดกรองแล้ว" value={assets.length} color="bg-green-500" />
          </div>
          <div className="flex flex-col sm:flex-row justify-end items-center bg-white p-3 rounded-xl shadow-sm border gap-4 shrink-0">
            <div className="flex items-center gap-3 w-full sm:w-auto">
              <button onClick={handleRefresh} className="p-2 text-[#6C248C] hover:bg-purple-50 rounded-lg border border-purple-100 transition-all flex items-center gap-2 group">
                <RefreshCw size={18} className={`${loading ? 'animate-spin' : 'group-hover:rotate-180'} transition-transform duration-500`} />
                <span className="text-xs font-medium hidden md:inline">รีโหลดข้อมูล</span>
              </button>
              <button onClick={() => setShowAddModal(true)} className="flex items-center justify-center gap-2 bg-[#6C248C] hover:bg-[#5a1e75] text-white px-5 py-2 rounded-lg text-sm font-medium shadow-md w-full sm:w-auto">
                <PlusCircle size={18} /><span>เพิ่มข้อมูล</span>
              </button>
            </div>
          </div>
          <div className="bg-white rounded-xl shadow-md border overflow-hidden flex flex-col flex-1 min-h-0">
            <AssetTable assets={assets} headers={headers} filters={filters} setFilters={setFilters} currentPage={currentPage} setCurrentPage={setCurrentPage} onUpdateAsset={handleUpdateAsset} loading={loading} />
          </div>
        </div>
      </main>

      {showAddModal && <AddAssetModal headers={headers} onClose={() => setShowAddModal(false)} onSubmit={handleAddAsset} />}
    </div>
  );
};

const SidebarItem: React.FC<{ icon: React.ReactNode, label: string, active: boolean, collapsed: boolean }> = ({ icon, label, active, collapsed }) => (
  <div className={`flex items-center gap-4 px-4 py-3 rounded-lg cursor-pointer transition-all ${active ? 'bg-white/20 text-white font-semibold' : 'text-purple-100 hover:bg-white/10 hover:text-white'}`}>
