สาเหตุที่ข้อมูลไม่ถูกบันทึก ทั้งที่พิกัดตรวจสอบแล้วว่าถูกต้อง มักเกิดจาก **3 ปัจจัยหลัก** ของ Google Apps Script ครับ:

1.  **CORS & Content-Type**: การส่ง `application/json` ผ่าน `fetch` มักจะติด Pre-flight (OPTIONS) ซึ่ง Apps Script ไม่รองรับ วิธีแก้ที่ชัวร์ที่สุดคือส่งเป็น `text/plain` แต่ข้างในเป็น JSON string
2.  **Apps Script Deployment**: ทุกครั้งที่มีการแก้ไขโค้ดในหน้า Apps Script คุณต้องกด **"Deploy" > "Manage Deployments" > "Edit (รูปดินสอ)" > "New Version"** เสมอ หากไม่เลือก New Version ตัว URL เดิมจะยังรันโค้ดชุดเก่าอยู่ครับ
3.  **Permission**: ต้องเลือก Execute as **"Me"** และ Who has access เป็น **"Anyone"**

ผมได้ปรับปรุง `sheetService.ts` ให้ส่งข้อมูลในรูปแบบที่ Apps Script รับได้แน่นอน 100% พร้อมปรับโค้ด Apps Script ให้รองรับการตรวจสอบ Error ได้ดีขึ้นครับ

### 1. ปรับปรุงโค้ดฝั่ง Apps Script (แนะนำให้คัดลอกไปวางใหม่)

```javascript
function doPost(e) {
  try {
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var sheet = ss.getSheetByName("Computername"); // ตรวจสอบชื่อแผ่นงานให้ตรงตัวสะกดเป๊ะๆ

    // ตรวจสอบว่ามีข้อมูลส่งมาหรือไม่
    if (!e.postData || !e.postData.contents) {
      return createResponse("Error: No post data");
    }

    var data = JSON.parse(e.postData.contents);
    var key1 = String(data.key1).trim(); // ค่าจาก Col A
    var key2 = String(data.key2).trim(); // ค่าจาก Col D
    var newName = data.newName;

    var values = sheet.getDataRange().getValues();
    var headers = values[0];

    // หาคอลัมน์ Computername
    var colCompNameIndex = headers.indexOf("Computername");
    if (colCompNameIndex === -1) {
      // ถ้าหาไม่เจอ ให้ลองหาคอลัมน์ที่ 3 (Index 2) เป็นค่าเริ่มต้น
      colCompNameIndex = 2; 
    }

    for (var i = 1; i < values.length; i++) {
      // ตรวจสอบ Index 0 (A) และ Index 3 (D) ให้ตรงกับที่ Log ในเว็บ
      if (String(values[i][0]).trim() === key1 && String(values[i][3]).trim() === key2) {
        sheet.getRange(i + 1, colCompNameIndex + 1).setValue(newName);
        return createResponse("Success");
      }
    }

    return createResponse("Error: Row not found for keys: " + key1 + ", " + key2);

  } catch (err) {
    return createResponse("Error: " + err.toString());
  }
}

// ฟังก์ชันช่วยส่งค่าตอบกลับเพื่อเลี่ยงปัญหา CORS
function createResponse(msg) {
  return ContentService.createTextOutput(msg).setMimeType(ContentService.MimeType.TEXT);
}
```

